var QUESTIONS_THEORY_8 = [
{type:"mcq",diff:"easy",en:{q:"Which of the following is the standard file extension for a modern MS PowerPoint presentation?",opts:[".pptx",".ptx",".pps",".doc"],ans:0,exp:"The standard file extension for Microsoft PowerPoint presentations created in versions 2007 and later is '.pptx'. This XML-based format offers better compression, improved security against macro viruses, and greater data recovery capabilities compared to the older '.ppt' binary format."},hi:{q:"आधुनिक MS PowerPoint प्रेजेंटेशन के लिए मानक फ़ाइल एक्सटेंशन निम्नलिखित में से कौन सा है?",opts:[".pptx",".ptx",".pps",".doc"],ans:0,exp:"संस्करण 2007 और उसके बाद के संस्करणों में बनाए गए Microsoft PowerPoint प्रस्तुतियों के लिए मानक फ़ाइल एक्सटेंशन '.pptx' है। यह XML-आधारित प्रारूप पुराने '.ppt' बाइनरी प्रारूप की तुलना में बेहतर संपीड़न, मैक्रो वायरस के खिलाफ उन्नत सुरक्षा और अधिक डेटा पुनर्प्राप्ति क्षमता प्रदान करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which keyboard shortcut is used to insert a completely new slide into an existing PowerPoint presentation?",opts:["Ctrl + N","Ctrl + M","Ctrl + S","Ctrl + I"],ans:1,exp:"Pressing 'Ctrl + M' instantly inserts a new slide immediately after the currently selected slide in the slide pane. It inherits the layout based on the preceding slide. In contrast, 'Ctrl + N' creates an entirely new, separate PowerPoint presentation file."},hi:{q:"मौजूदा PowerPoint प्रेजेंटेशन में एक बिल्कुल नई स्लाइड डालने के लिए किस कीबोर्ड शॉर्टकट का उपयोग किया जाता है?",opts:["Ctrl + N","Ctrl + M","Ctrl + S","Ctrl + I"],ans:1,exp:"'Ctrl + M' दबाने पर स्लाइड पैन में वर्तमान में चयनित स्लाइड के ठीक बाद तुरंत एक नई स्लाइड आ जाती है। यह पिछली स्लाइड के आधार पर लेआउट प्राप्त करता है। इसके विपरीत, 'Ctrl + N' एक पूरी तरह से नई, अलग PowerPoint प्रेजेंटेशन फ़ाइल बनाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the primary fundamental unit of a PowerPoint presentation called?",opts:["Worksheet","Document","Slide","Page"],ans:2,exp:"A 'Slide' is the single, foundational page or screen of a PowerPoint presentation. Users add text, graphics, videos, and animations to individual slides. When presented, these slides are displayed sequentially to the audience, forming the complete visual presentation."},hi:{q:"PowerPoint प्रेजेंटेशन की प्राथमिक मूलभूत इकाई को क्या कहा जाता है?",opts:["वर्कशीट (Worksheet)","दस्तावेज़ (Document)","स्लाइड (Slide)","पृष्ठ (Page)"],ans:2,exp:"एक 'स्लाइड' (Slide) PowerPoint प्रेजेंटेशन का एकल, मूलभूत पृष्ठ या स्क्रीन है। उपयोगकर्ता अलग-अलग स्लाइड में टेक्स्ट, ग्राफिक्स, वीडियो और एनिमेशन जोड़ते हैं। प्रस्तुत किए जाने पर, ये स्लाइड दर्शकों को क्रमिक रूप से प्रदर्शित की जाती हैं, जिससे संपूर्ण दृश्य प्रस्तुति बनती है।"}},
{type:"mcq",diff:"easy",en:{q:"Which function key is traditionally used to start a slide show from the very first slide?",opts:["F2","F5","F7","F12"],ans:1,exp:"Pressing the 'F5' key instantly launches the presentation in full-screen Slide Show mode starting from slide number 1, regardless of which slide is currently active. To start from the currently selected slide, the combination 'Shift + F5' is used."},hi:{q:"पारंपरिक रूप से पहली स्लाइड से स्लाइड शो शुरू करने के लिए किस फ़ंक्शन कुंजी का उपयोग किया जाता है?",opts:["F2","F5","F7","F12"],ans:1,exp:"'F5' कुंजी दबाने से प्रेजेंटेशन तुरंत फुल-स्क्रीन स्लाइड शो मोड में स्लाइड नंबर 1 से शुरू हो जाता है, भले ही वर्तमान में कौन सी स्लाइड सक्रिय हो। वर्तमान में चयनित स्लाइड से शुरू करने के लिए, 'Shift + F5' संयोजन का उपयोग किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the name of the box with dotted borders on a slide that holds text, pictures, or charts?",opts:["Text box","Placeholder","Frame","Container"],ans:1,exp:"A 'Placeholder' is a pre-formatted container on a slide layout, indicated by dotted borders. It prompts the user to 'Click to add text' or provides icons to quickly insert tables, charts, SmartArt, or media. Placeholders dictate the overall structural layout of the slide."},hi:{q:"एक स्लाइड पर बिंदीदार सीमाओं वाले बॉक्स का नाम क्या है जिसमें टेक्स्ट, चित्र या चार्ट होते हैं?",opts:["टेक्स्ट बॉक्स (Text box)","प्लेसहोल्डर (Placeholder)","फ़्रेम (Frame)","कंटेनर (Container)"],ans:1,exp:"एक 'प्लेसहोल्डर' (Placeholder) एक स्लाइड लेआउट पर एक पूर्व-स्वरूपित कंटेनर है, जिसे बिंदीदार सीमाओं द्वारा दर्शाया जाता है। यह उपयोगकर्ता को 'टेक्स्ट जोड़ने के लिए क्लिक करें' का संकेत देता है या टेबल, चार्ट, स्मार्टआर्ट या मीडिया को तुरंत सम्मिलित करने के लिए आइकन प्रदान करता है। प्लेसहोल्डर स्लाइड के समग्र संरचनात्मक लेआउट को निर्धारित करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which default view is used for creating and editing individual slides in PowerPoint?",opts:["Slide Sorter View","Reading View","Normal View","Notes Page View"],ans:2,exp:"'Normal View' is the standard, primary editing interface in PowerPoint. It consists of three main working areas: the slide pane in the center for active editing, the slide thumbnails on the left for navigation, and the notes pane at the bottom for speaker notes."},hi:{q:"PowerPoint में व्यक्तिगत स्लाइड बनाने और संपादित करने के लिए किस डिफ़ॉल्ट दृश्य का उपयोग किया जाता है?",opts:["स्लाइड सॉर्टर व्यू","रीडिंग व्यू","नॉर्मल व्यू (Normal View)","नोट्स पेज व्यू"],ans:2,exp:"'नॉर्मल व्यू' PowerPoint में मानक, प्राथमिक संपादन इंटरफ़ेस है। इसमें तीन मुख्य कार्य क्षेत्र होते हैं: सक्रिय संपादन के लिए केंद्र में स्लाइड पैन, नेविगेशन के लिए बाईं ओर स्लाइड थंबनेल, और स्पीकर नोट्स के लिए सबसे नीचे नोट्स पैन।"}},
{type:"mcq",diff:"easy",en:{q:"Under which Ribbon tab would you find the options to insert a picture or a shape?",opts:["Home tab","Design tab","Insert tab","Animations tab"],ans:2,exp:"The 'Insert' tab contains all commands related to adding objects to a slide. This includes inserting pictures, shapes, SmartArt graphics, charts, tables, text boxes, and multimedia files like audio and video, allowing the user to construct visually rich slides."},hi:{q:"आप किस रिबन टैब के अंतर्गत चित्र या आकार सम्मिलित करने के विकल्प पाएंगे?",opts:["होम टैब","डिज़ाइन टैब","इंसर्ट टैब (Insert tab)","एनिमेशन टैब"],ans:2,exp:"'इंसर्ट' (Insert) टैब में स्लाइड में ऑब्जेक्ट जोड़ने से संबंधित सभी कमांड होते हैं। इसमें चित्र, आकार, स्मार्टआर्ट ग्राफिक्स, चार्ट, टेबल, टेक्स्ट बॉक्स और ऑडियो और वीडियो जैसे मल्टीमीडिया फ़ाइलों को सम्मिलित करना शामिल है, जिससे उपयोगकर्ता दृश्य रूप से समृद्ध स्लाइड बना सकते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What is the maximum zoom percentage allowed in an MS PowerPoint presentation?",opts:["100%","200%","400%","500%"],ans:2,exp:"Microsoft PowerPoint allows users to magnify the slide working area up to a maximum of 400%. This high level of zoom is particularly useful for precision alignment, intricate graphic editing, and adjusting minute details on complex slide layouts."},hi:{q:"MS PowerPoint प्रेजेंटेशन में अनुमत अधिकतम ज़ूम प्रतिशत क्या है?",opts:["100%","200%","400%","500%"],ans:2,exp:"Microsoft PowerPoint उपयोगकर्ताओं को स्लाइड वर्किंग एरिया को अधिकतम 400% तक बड़ा करने की अनुमति देता है। ज़ूम का यह उच्च स्तर सटीक संरेखण, जटिल ग्राफिक संपादन और जटिल स्लाइड लेआउट पर सूक्ष्म विवरण समायोजित करने के लिए विशेष रूप से उपयोगी है।"}},
{type:"mcq",diff:"easy",en:{q:"Which view displays miniature versions of all slides, making it easy to rearrange or delete them?",opts:["Normal View","Slide Sorter View","Master View","Slide Show View"],ans:1,exp:"'Slide Sorter View' gives a bird's-eye view of the entire presentation by displaying all slides as horizontal thumbnails. It is the most efficient view for drag-and-drop reordering, applying global transitions, or deleting multiple slides simultaneously."},hi:{q:"कौन सा दृश्य सभी स्लाइडों के लघु संस्करण (thumbnails) प्रदर्शित करता है, जिससे उन्हें पुनर्व्यवस्थित करना या हटाना आसान हो जाता है?",opts:["नॉर्मल व्यू","स्लाइड सॉर्टर व्यू (Slide Sorter View)","मास्टर व्यू","स्लाइड शो व्यू"],ans:1,exp:"'स्लाइड सॉर्टर व्यू' सभी स्लाइडों को क्षैतिज थंबनेल के रूप में प्रदर्शित करके संपूर्ण प्रस्तुति का विहंगम दृश्य (bird's-eye view) देता है। यह ड्रैग-एंड-ड्रॉप रीऑर्डरिंग, ग्लोबल ट्रांज़िशन लागू करने या एक साथ कई स्लाइडों को हटाने के लिए सबसे कुशल दृश्य है।"}},
{type:"mcq",diff:"easy",en:{q:"Which key is universally used to stop or exit a running slide show in PowerPoint?",opts:["Enter","Spacebar","Esc","Shift"],ans:2,exp:"The 'Esc' (Escape) key immediately terminates an active full-screen Slide Show and returns the user to the PowerPoint editing interface (usually Normal view). It is the standard hardware interrupt for exiting presentation mode."},hi:{q:"PowerPoint में चल रहे स्लाइड शो को रोकने या बाहर निकलने के लिए सार्वभौमिक रूप से किस कुंजी का उपयोग किया जाता है?",opts:["Enter","Spacebar","Esc","Shift"],ans:2,exp:"'Esc' (एस्केप) कुंजी तुरंत एक सक्रिय फुल-स्क्रीन स्लाइड शो को समाप्त कर देती है और उपयोगकर्ता को PowerPoint संपादन इंटरफ़ेस (आमतौर पर सामान्य दृश्य) में वापस कर देती है। यह प्रस्तुति मोड से बाहर निकलने के लिए मानक हार्डवेयर इंटरप्ट है।"}},
{type:"mcq",diff:"easy",en:{q:"What is a pre-designed presentation with background styles, colors, and layouts called?",opts:["Blueprint","Template","Document","Master"],ans:1,exp:"A 'Template' is a pre-configured presentation file that provides a unified design scheme, including preset background images, color palettes, font styles, and placeholder layouts. Using a template allows a user to rapidly create a professional-looking presentation without designing from scratch."},hi:{q:"पृष्ठभूमि शैलियों, रंगों और लेआउट के साथ पूर्व-डिज़ाइन की गई प्रस्तुति को क्या कहा जाता है?",opts:["ब्लूप्रिंट (Blueprint)","टेम्पलेट (Template)","दस्तावेज़ (Document)","मास्टर (Master)"],ans:1,exp:"एक 'टेम्पलेट' (Template) एक पूर्व-कॉन्फ़िगर की गई प्रस्तुति फ़ाइल है जो एक एकीकृत डिज़ाइन योजना प्रदान करती है, जिसमें पूर्व निर्धारित पृष्ठभूमि चित्र, रंग पट्टियाँ, फ़ॉन्ट शैलियाँ और प्लेसहोल्डर लेआउट शामिल हैं। टेम्पलेट का उपयोग करने से उपयोगकर्ता खरोंच से डिजाइन किए बिना पेशेवर दिखने वाली प्रस्तुति तेजी से बना सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which default page orientation is applied to slides when a new PowerPoint file is created?",opts:["Portrait","Landscape","Square","Vertical"],ans:1,exp:"By default, PowerPoint slides are oriented in 'Landscape' mode (wider than they are tall). This horizontal orientation is optimized for modern display monitors, projectors, and widescreen TVs, typically using aspect ratios like 16:9 or 4:3 for maximum visual impact."},hi:{q:"जब कोई नई PowerPoint फ़ाइल बनाई जाती है तो स्लाइड पर कौन सा डिफ़ॉルト पृष्ठ ओरिएंटेशन (page orientation) लागू होता है?",opts:["पोर्ट्रेट (Portrait)","लैंडस्केप (Landscape)","वर्गाकार (Square)","वर्टिकल (Vertical)"],ans:1,exp:"डिफ़ॉल्ट रूप से, PowerPoint स्लाइड 'लैंडस्केप' मोड (लंबे होने की तुलना में व्यापक) में उन्मुख होते हैं। यह क्षैतिज अभिविन्यास आधुनिक डिस्प्ले मॉनिटर, प्रोजेक्टर और वाइडस्क्रीन टीवी के लिए अनुकूलित है, जो आमतौर पर अधिकतम दृश्य प्रभाव के लिए 16:9 या 4:3 जैसे पहलू अनुपात (aspect ratios) का उपयोग करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which shortcut combination saves the current presentation?",opts:["Ctrl + S","Ctrl + P","Ctrl + X","Ctrl + O"],ans:0,exp:"'Ctrl + S' invokes the Save command. If the presentation has not been saved before, it opens the 'Save As' dialog, allowing the user to name the file and choose a storage location. If previously saved, it silently overwrites the existing file with the latest changes."},hi:{q:"कौन सा शॉर्टकट संयोजन वर्तमान प्रस्तुति को सहेजता है?",opts:["Ctrl + S","Ctrl + P","Ctrl + X","Ctrl + O"],ans:0,exp:"'Ctrl + S' सेव (Save) कमांड को आमंत्रित करता है। यदि प्रस्तुति पहले सहेजी नहीं गई है, तो यह 'सेव एज़' (Save As) संवाद खोलता है, जिससे उपयोगकर्ता फ़ाइल को नाम दे सकता है और एक भंडारण स्थान चुन सकता है। यदि पहले सहेजा गया है, तो यह मौजूदा फ़ाइल को नवीनतम परिवर्तनों के साथ चुपचाप अधिलेखित (overwrite) कर देता है।"}},
{type:"mcq",diff:"easy",en:{q:"In PowerPoint, what does the Format Painter tool do?",opts:["Paints the background of the slide","Copies formatting from one object and applies it to another","Draws custom shapes","Formats the hard drive"],ans:1,exp:"The 'Format Painter' copies all formatting attributes—such as font style, color, size, and effects—from a selected text or object. The user can then 'paint' or apply those exact formatting attributes to another piece of text or object, ensuring perfect visual consistency."},hi:{q:"PowerPoint में, फॉर्मेट पेंटर (Format Painter) टूल क्या करता है?",opts:["स्लाइड की पृष्ठभूमि को पेंट करता है","एक ऑब्जेक्ट से स्वरूपण (formatting) की प्रतिलिपि बनाता है और इसे दूसरे पर लागू करता है","कस्टम आकार खींचता है","हार्ड ड्राइव को फ़ॉर्मेट करता है"],ans:1,exp:"'फॉर्मेट पेंटर' चयनित टेक्स्ट या ऑब्जेक्ट से सभी स्वरूपण विशेषताओं-जैसे फ़ॉन्ट शैली, रंग, आकार और प्रभावों-की प्रतिलिपि बनाता है। उपयोगकर्ता तब उन सटीक स्वरूपण विशेषताओं को टेक्स्ट या ऑब्जेक्ट के दूसरे टुकड़े पर 'पेंट' या लागू कर सकता है, जिससे पूर्ण दृश्य स्थिरता सुनिश्चित होती है।"}},
{type:"mcq",diff:"easy",en:{q:"Which key is used to delete a selected slide in the left thumbnail pane?",opts:["Enter","Shift","Backspace or Delete","Alt"],ans:2,exp:"When a slide is selected in the left navigation pane or Slide Sorter view, pressing either the 'Delete' key or the 'Backspace' key will immediately remove that entire slide from the presentation file. This action can be undone using Ctrl+Z."},hi:{q:"बाएँ थंबनेल पैन में चयनित स्लाइड को हटाने के लिए किस कुंजी का उपयोग किया जाता है?",opts:["Enter","Shift","Backspace या Delete","Alt"],ans:2,exp:"जब बाएँ नेविगेशन पैन या स्लाइड सॉर्टर व्यू में किसी स्लाइड का चयन किया जाता है, तो 'Delete' कुंजी या 'Backspace' कुंजी दबाने से वह पूरी स्लाइड प्रस्तुति फ़ाइल से तुरंत हट जाएगी। इस क्रिया को Ctrl+Z का उपयोग करके पूर्ववत (undo) किया जा सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which tab is specifically used to change the font size, color, and text alignment?",opts:["Insert","Design","Home","Review"],ans:2,exp:"The 'Home' tab is the default active tab and houses the most frequently used commands. It contains the Font and Paragraph groups, providing immediate access to text formatting tools like bold, italics, font size, color, bullet points, and text alignment options."},hi:{q:"फ़ॉन्ट आकार, रंग और टेक्स्ट संरेखण (alignment) को बदलने के लिए विशेष रूप से किस टैब का उपयोग किया जाता है?",opts:["Insert","Design","Home","Review"],ans:2,exp:"'होम' (Home) टैब डिफ़ॉल्ट सक्रिय टैब है और इसमें सबसे अधिक उपयोग किए जाने वाले कमांड होते हैं। इसमें फ़ॉन्ट और पैराग्राफ समूह होते हैं, जो बोल्ड, इटैलिक, फ़ॉन्ट आकार, रंग, बुलेट पॉइंट और टेक्स्ट संरेखण विकल्पों जैसे टेक्स्ट फ़ॉर्मेटिंग टूल तक तत्काल पहुंच प्रदान करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What happens when you press 'Ctrl + A' in the slide thumbnail pane?",opts:["Adds a new slide","Selects all slides in the presentation","Aligns text to the center","Opens the Animation pane"],ans:1,exp:"Pressing 'Ctrl + A' invokes the 'Select All' command. When the focus is on the left slide thumbnail pane or Slide Sorter view, this command selects every single slide in the presentation, allowing bulk operations like deleting, copying, or applying global transitions."},hi:{q:"स्लाइड थंबनेल पैन में 'Ctrl + A' दबाने पर क्या होता है?",opts:["एक नई स्लाइड जोड़ता है","प्रेजेंटेशन की सभी स्लाइडों का चयन करता है","टेक्स्ट को केंद्र में संरेखित करता है","एनिमेशन पैन खोलता है"],ans:1,exp:"'Ctrl + A' दबाने पर 'Select All' (सभी चुनें) कमांड लागू होता है। जब फोकस बाएँ स्लाइड थंबनेल पैन या स्लाइड सॉर्टर व्यू पर होता है, तो यह कमांड प्रस्तुति में हर एक स्लाइड का चयन करता है, जिससे हटाने, कॉपी करने या वैश्विक संक्रमण (global transitions) लागू करने जैसे थोक संचालन की अनुमति मिलती है।"}},
{type:"mcq",diff:"easy",en:{q:"Which option allows you to reverse your last action in PowerPoint?",opts:["Undo (Ctrl + Z)","Redo (Ctrl + Y)","Cut (Ctrl + X)","Paste (Ctrl + V)"],ans:0,exp:"The 'Undo' command, triggered by 'Ctrl + Z', reverts the presentation state back one step, effectively erasing the very last action performed. PowerPoint maintains an undo history, allowing users to press it multiple times to step back through recent changes and fix mistakes."},hi:{q:"कौन सा विकल्प आपको PowerPoint में अपनी अंतिम क्रिया को उलटने (reverse) की अनुमति देता है?",opts:["Undo (Ctrl + Z)","Redo (Ctrl + Y)","Cut (Ctrl + X)","Paste (Ctrl + V)"],ans:0,exp:"'अनडू' (Undo) कमांड, जो 'Ctrl + Z' द्वारा ट्रिगर होता है, प्रस्तुति की स्थिति को एक कदम पीछे ले जाता है, जो प्रभावी रूप से किए गए अंतिम कार्य को मिटा देता है। PowerPoint एक पूर्ववत इतिहास (undo history) बनाए रखता है, जिससे उपयोगकर्ता हाल के परिवर्तनों के माध्यम से वापस जाने और गलतियों को सुधारने के लिए इसे कई बार दबा सकते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What is the shortcut to open an existing PowerPoint presentation?",opts:["Ctrl + E","Ctrl + O","Ctrl + P","Ctrl + W"],ans:1,exp:"'Ctrl + O' is the standard shortcut to Open a file. It directs the user to the Open menu in the Backstage view, allowing them to browse local drives, network locations, or cloud storage (like OneDrive) to locate and open an existing .pptx file."},hi:{q:"मौजूदा PowerPoint प्रेजेंटेशन खोलने का शॉर्टकट क्या है?",opts:["Ctrl + E","Ctrl + O","Ctrl + P","Ctrl + W"],ans:1,exp:"फ़ाइल खोलने के लिए 'Ctrl + O' मानक शॉर्टकट है। यह उपयोगकर्ता को बैकस्टेज दृश्य में ओपन मेनू पर निर्देशित करता है, जिससे वे मौजूदा .pptx फ़ाइल का पता लगाने और खोलने के लिए स्थानीय ड्राइव, नेटवर्क स्थान या क्लाउड स्टोरेज (जैसे वनड्राइव) ब्राउज़ कर सकते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"If you want to place text over an image, which tool should you insert?",opts:["WordArt","Chart","Text Box","SmartArt"],ans:2,exp:"A 'Text Box' is a floating container that allows text to be typed anywhere on a slide, completely independent of the slide's master placeholders. It can be dragged and positioned directly over images, shapes, or videos to overlay descriptive captions or labels."},hi:{q:"यदि आप किसी छवि के ऊपर टेक्स्ट रखना चाहते हैं, तो आपको कौन सा टूल सम्मिलित करना चाहिए?",opts:["वर्डआर्ट (WordArt)","चार्ट (Chart)","टेक्स्ट बॉक्स (Text Box)","स्मार्टआर्ट (SmartArt)"],ans:2,exp:"एक 'टेक्स्ट बॉक्स' एक फ्लोटिंग कंटेनर है जो टेक्स्ट को स्लाइड पर कहीं भी टाइप करने की अनुमति देता है, जो स्लाइड के मास्टर प्लेसहोल्डर्स से पूरी तरह स्वतंत्र है। इसे वर्णनात्मक कैप्शन या लेबल को ओवरले करने के लिए चित्र, आकार या वीडियो पर सीधे खींचा और रखा जा सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following describes the 'Title Slide' layout?",opts:["A blank slide with no placeholders","A slide used only for inserting videos","The default first slide used to introduce the presentation topic","A slide containing only a large table"],ans:2,exp:"The 'Title Slide' is the default layout applied to the very first slide of a new presentation. It typically features two centrally aligned text placeholders: a prominent one for the main presentation title and a smaller one beneath it for a subtitle, presenter name, or date."},hi:{q:"निम्नलिखित में से कौन सा 'टाइटल स्लाइड' (Title Slide) लेआउट का वर्णन करता है?",opts:["बिना प्लेसहोल्डर वाली खाली स्लाइड","केवल वीडियो सम्मिलित करने के लिए उपयोग की जाने वाली स्लाइड","प्रस्तुति विषय को पेश करने के लिए उपयोग की जाने वाली डिफ़ॉल्ट पहली स्लाइड","केवल एक बड़ी तालिका वाली स्लाइड"],ans:2,exp:"'टाइटल स्लाइड' एक नई प्रस्तुति की पहली स्लाइड पर लागू डिफ़ॉल्ट लेआउट है। इसमें आम तौर पर दो केंद्रीय रूप से संरेखित टेक्स्ट प्लेसहोल्डर होते हैं: एक मुख्य प्रस्तुति शीर्षक के लिए एक प्रमुख और एक उपशीर्षक, प्रस्तुतकर्ता नाम या दिनांक के लिए इसके नीचे एक छोटा सा।"}},
{type:"mcq",diff:"easy",en:{q:"Which shortcut combination copies selected text or objects?",opts:["Ctrl + X","Ctrl + C","Ctrl + P","Ctrl + Z"],ans:1,exp:"'Ctrl + C' executes the Copy command. It takes a perfect duplicate of the selected text, shape, or slide and temporarily stores it in the system Clipboard. This data remains in the Clipboard until it is pasted elsewhere using Ctrl + V or overwritten by a new copy action."},hi:{q:"कौन सा शॉर्टकट संयोजन चयनित टेक्स्ट या ऑब्जेक्ट की प्रतिलिपि (copy) बनाता है?",opts:["Ctrl + X","Ctrl + C","Ctrl + P","Ctrl + Z"],ans:1,exp:"'Ctrl + C' कॉपी कमांड को निष्पादित करता है। यह चयनित टेक्स्ट, आकार या स्लाइड का एक सही डुप्लिकेट लेता है और इसे अस्थायी रूप से सिस्टम क्लिपबोर्ड में संग्रहीत करता है। यह डेटा क्लिपबोर्ड में तब तक रहता है जब तक कि इसे Ctrl + V का उपयोग करके कहीं और चिपकाया नहीं जाता है या एक नई प्रतिलिपि क्रिया द्वारा अधिलेखित नहीं किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which key combination allows you to paste the copied content?",opts:["Ctrl + C","Ctrl + X","Ctrl + V","Ctrl + B"],ans:2,exp:"'Ctrl + V' is the universal command to Paste. It retrieves whatever data (text, images, slides) is currently residing in the computer's active Clipboard and inserts it into the currently selected location within the PowerPoint slide or thumbnail pane."},hi:{q:"कौन सा कुंजी संयोजन आपको कॉपी की गई सामग्री को पेस्ट करने की अनुमति देता है?",opts:["Ctrl + C","Ctrl + X","Ctrl + V","Ctrl + B"],ans:2,exp:"पेस्ट (Paste) करने के लिए 'Ctrl + V' सार्वभौमिक कमांड है। यह कंप्यूटर के सक्रिय क्लिपबोर्ड में जो भी डेटा (टेक्स्ट, चित्र, स्लाइड) वर्तमान में रहता है उसे पुनः प्राप्त करता है और इसे PowerPoint स्लाइड या थंबनेल पैन के भीतर वर्तमान में चयनित स्थान पर सम्मिलित करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the function of the 'Design' tab in the Ribbon?",opts:["To insert audio and video","To apply pre-built themes, colors, and background styles to slides","To spell check the document","To add animation effects to text"],ans:1,exp:"The 'Design' tab is dedicated to the overall aesthetic appearance of the presentation. It allows users to quickly apply global Themes (which dictate fonts, colors, and effects), change the Slide Size (e.g., 16:9 or 4:3), and format the slide background properties."},hi:{q:"रिबन में 'डिज़ाइन' (Design) टैब का कार्य क्या है?",opts:["ऑडियो और वीडियो डालने के लिए","स्लाइड पर पूर्व-निर्मित थीम, रंग और पृष्ठभूमि शैली लागू करने के लिए","दस्तावेज़ की वर्तनी जांचने के लिए","टेक्स्ट में एनीमेशन प्रभाव जोड़ने के लिए"],ans:1,exp:"'डिज़ाइन' टैब प्रस्तुति की समग्र सौंदर्य उपस्थिति को समर्पित है। यह उपयोगकर्ताओं को वैश्विक थीम्स (जो फोंट, रंग और प्रभाव निर्धारित करते हैं) को जल्दी से लागू करने, स्लाइड आकार (जैसे, 16:9 या 4:3) को बदलने और स्लाइड पृष्ठभूमि गुणों को प्रारूपित करने की अनुमति देता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which shortcut combination is used to make selected text bold?",opts:["Ctrl + B","Ctrl + U","Ctrl + I","Ctrl + D"],ans:0,exp:"Pressing 'Ctrl + B' toggles the Bold font style for the selected text. It makes the characters thicker and heavier, which is extremely useful for emphasizing key words, titles, or critical data points within a slide's text placeholders."},hi:{q:"चयनित टेक्स्ट को बोल्ड करने के लिए किस शॉर्टकट संयोजन का उपयोग किया जाता है?",opts:["Ctrl + B","Ctrl + U","Ctrl + I","Ctrl + D"],ans:0,exp:"'Ctrl + B' दबाने से चयनित टेक्स्ट के लिए बोल्ड फ़ॉन्ट शैली टॉगल हो जाती है। यह पात्रों को मोटा और भारी बनाता है, जो किसी स्लाइड के टेक्स्ट प्लेसहोल्डर्स के भीतर प्रमुख शब्दों, शीर्षकों या महत्वपूर्ण डेटा बिंदुओं पर जोर देने के लिए अत्यंत उपयोगी है।"}},
{type:"mcq",diff:"easy",en:{q:"Which key is used to Undo your last action?",opts:["Ctrl + Y","Ctrl + U","Ctrl + Z","Ctrl + X"],ans:2,exp:"The Undo command, linked to 'Ctrl + Z', is a critical safety feature. If you accidentally delete an object, move a picture incorrectly, or apply the wrong format, pressing Ctrl + Z immediately reverts the file state to exactly how it was before that specific action."},hi:{q:"आपकी अंतिम क्रिया को पूर्ववत (Undo) करने के लिए किस कुंजी का उपयोग किया जाता है?",opts:["Ctrl + Y","Ctrl + U","Ctrl + Z","Ctrl + X"],ans:2,exp:"'Ctrl + Z' से जुड़ा पूर्ववत (Undo) कमांड एक महत्वपूर्ण सुरक्षा विशेषता है। यदि आप गलती से किसी ऑब्जेक्ट को हटा देते हैं, किसी चित्र को गलत तरीके से ले जाते हैं, या गलत प्रारूप लागू करते हैं, तो Ctrl + Z दबाने से फ़ाइल की स्थिति तुरंत उसी स्थिति में वापस आ जाती है जैसे वह उस विशिष्ट क्रिया से पहले थी।"}},
{type:"mcq",diff:"easy",en:{q:"What does the 'Redo' command do?",opts:["Deletes the document","Saves the document","Reverses the action of the 'Undo' command","Closes the presentation"],ans:2,exp:"The 'Redo' command, operated by 'Ctrl + Y', effectively undoes an 'Undo'. If a user presses Ctrl + Z and realizes they actually wanted to keep that change, pressing Ctrl + Y restores the action that was just reversed, moving forward in the edit history."},hi:{q:"'रीडू' (Redo) कमांड क्या करता है?",opts:["दस्तावेज़ हटाता है","दस्तावेज़ सहेजता है","'अंडू' (Undo) कमांड की क्रिया को उलट देता है","प्रेजेंटेशन बंद करता है"],ans:2,exp:"'Ctrl + Y' द्वारा संचालित 'रीडू' (Redo) कमांड प्रभावी रूप से 'अंडू' को पूर्ववत कर देता है। यदि कोई उपयोगकर्ता Ctrl + Z दबाता है और महसूस करता है कि वे वास्तव में उस परिवर्तन को रखना चाहते थे, तो Ctrl + Y दबाने से वह क्रिया बहाल हो जाती है जो अभी उलट गई थी, संपादन इतिहास में आगे बढ़ रही है।"}},
{type:"mcq",diff:"easy",en:{q:"Which shortcut combination is used to Cut a selected object?",opts:["Ctrl + C","Ctrl + X","Ctrl + V","Ctrl + K"],ans:1,exp:"'Ctrl + X' invokes the Cut command. Unlike Copy, cutting actually removes the selected text or object from its current location on the slide and stores it in the Clipboard. It is primarily used to move an object from one slide to another by cutting and pasting."},hi:{q:"चयनित ऑब्जेक्ट को कट (Cut) करने के लिए किस शॉर्टकट संयोजन का उपयोग किया जाता है?",opts:["Ctrl + C","Ctrl + X","Ctrl + V","Ctrl + K"],ans:1,exp:"'Ctrl + X' कट कमांड लागू करता है। कॉपी के विपरीत, काटना (cutting) वास्तव में चयनित टेक्स्ट या ऑब्जेक्ट को स्लाइड पर उसके वर्तमान स्थान से हटा देता है और इसे क्लिपबोर्ड में संग्रहीत करता है। इसका उपयोग मुख्य रूप से किसी ऑब्जेक्ट को काटकर और चिपकाकर एक स्लाइड से दूसरी स्लाइड में ले जाने के लिए किया जाता है।"}},
{type:"tf",diff:"easy",en:{q:"Pressing Ctrl+M and Ctrl+N in PowerPoint perform exactly the same function.",opts:["True","False"],ans:1,exp:"False. They are distinctly different. 'Ctrl + M' inserts a new Slide into the currently open presentation file. 'Ctrl + N' creates a completely new, separate PowerPoint presentation File (e.g., Presentation2)."},hi:{q:"PowerPoint में Ctrl+M और Ctrl+N दबाने से बिल्कुल एक ही कार्य होता है।",opts:["सही","गलत"],ans:1,exp:"गलत। वे स्पष्ट रूप से भिन्न हैं। 'Ctrl + M' वर्तमान में खुली प्रस्तुति फ़ाइल में एक नई स्लाइड सम्मिलित करता है। 'Ctrl + N' एक पूरी तरह से नई, अलग PowerPoint प्रेजेंटेशन फ़ाइल (उदा., Presentation2) बनाता है।"}},
{type:"tf",diff:"easy",en:{q:"You can insert external video files directly into a PowerPoint slide.",opts:["True","False"],ans:0,exp:"True. PowerPoint robustly supports multimedia. Users can navigate to Insert > Video to embed local video files stored on their PC or link to online videos. The video can then be resized, cropped, and set to play automatically or on click."},hi:{q:"आप बाहरी वीडियो फ़ाइलों को सीधे PowerPoint स्लाइड में डाल सकते हैं।",opts:["सही","गलत"],ans:0,exp:"सही। PowerPoint मजबूती से मल्टीमीडिया का समर्थन करता है। उपयोगकर्ता अपने पीसी पर संग्रहीत स्थानीय वीडियो फ़ाइलों को एम्बेड करने या ऑनलाइन वीडियो से लिंक करने के लिए इंसर्ट > वीडियो (Insert > Video) पर नेविगेट कर सकते हैं। फिर वीडियो का आकार बदला जा सकता है, काटा जा सकता है, और स्वचालित रूप से या क्लिक पर चलने के लिए सेट किया जा सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the functional difference between a 'Transition' and an 'Animation' in PowerPoint?",opts:["Animations apply to whole slides; Transitions apply to text","Transitions are motion effects applied when moving from one slide to the next; Animations move individual objects on a slide","Transitions add background music; Animations add video","There is no difference, they are identical terms"],ans:1,exp:"This is a critical distinction in PowerPoint. 'Transitions' govern the visual cinematic effect that occurs exactly when the presentation shifts from one whole slide to the next. 'Animations' govern the movement of specific elements (like text boxes, pictures, or shapes) within a single slide."},hi:{q:"PowerPoint में 'ट्रांज़िशन' (Transition) और 'एनीमेशन' (Animation) के बीच कार्यात्मक अंतर क्या है?",opts:["एनिमेशन पूरी स्लाइड पर लागू होते हैं; ट्रांज़िशन टेक्स्ट पर लागू होते हैं","एक स्लाइड से दूसरी स्लाइड पर जाने पर ट्रांज़िशन मोशन प्रभाव लागू होते हैं; एनिमेशन एक स्लाइड पर अलग-अलग ऑब्जेक्ट ले जाते हैं","ट्रांज़िशन पृष्ठभूमि संगीत जोड़ते हैं; एनिमेशन वीडियो जोड़ते हैं","कोई अंतर नहीं है, वे समान शब्द हैं"],ans:1,exp:"यह PowerPoint में एक महत्वपूर्ण अंतर है। 'ट्रांज़िशन' उस दृश्य सिनेमाई प्रभाव को नियंत्रित करते हैं जो ठीक तब होता है जब प्रस्तुति एक पूरी स्लाइड से अगली स्लाइड में जाती है। 'एनीमेशन' एक स्लाइड के भीतर विशिष्ट तत्वों (जैसे टेक्स्ट बॉक्स, चित्र या आकार) की गति को नियंत्रित करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"What is the core purpose of the 'Slide Master' feature?",opts:["To convert the presentation into a video","To universally control the default layout, fonts, colors, and background of all slides in a presentation","To automatically translate text","To rehearse the timings of the slide show"],ans:1,exp:"The 'Slide Master' acts as the foundational blueprint for a presentation. Making a change on the Slide Master (like adding a company logo or changing a title font) automatically cascades that exact change to every associated slide layout, ensuring perfect design consistency and saving immense editing time."},hi:{q:"'स्लाइड मास्टर' (Slide Master) सुविधा का मुख्य उद्देश्य क्या है?",opts:["प्रस्तुति को वीडियो में बदलने के लिए","एक प्रस्तुति में सभी स्लाइडों के डिफ़ॉल्ट लेआउट, फ़ॉन्ट, रंग और पृष्ठभूमि को सार्वभौमिक रूप से नियंत्रित करने के लिए","टेक्स्ट का स्वचालित रूप से अनुवाद करने के लिए","स्लाइड शो के समय का पूर्वाभ्यास करने के लिए"],ans:1,exp:"'स्लाइड मास्टर' एक प्रस्तुति के लिए मूलभूत खाका (blueprint) के रूप में कार्य करता है। स्लाइड मास्टर पर परिवर्तन करना (जैसे कंपनी का लोगो जोड़ना या शीर्षक फ़ॉन्ट बदलना) स्वचालित रूप से उस सटीक परिवर्तन को हर संबंधित स्लाइड लेआउट में बदल देता है, जिससे सही डिज़ाइन स्थिरता सुनिश्चित होती है और संपादन समय की काफी बचत होती है।"}},
{type:"mcq",diff:"medium",en:{q:"When printing a presentation, what format is specifically designed to distribute physical copies to the audience with space for taking notes?",opts:["Full Page Slides","Outline View","Handouts","Notes Pages"],ans:2,exp:"'Handouts' are a specific print layout that puts multiple miniature slides on a single sheet of printed paper (e.g., 2, 3, 4, 6, or 9 slides per page). The '3 Slides' layout is particularly popular because it prints lines next to each slide specifically for the audience to write notes."},hi:{q:"प्रेजेंटेशन को प्रिंट करते समय, दर्शकों को नोट्स लेने के लिए जगह के साथ भौतिक प्रतियां वितरित करने के लिए विशेष रूप से कौन सा प्रारूप डिज़ाइन किया गया है?",opts:["पूर्ण पृष्ठ स्लाइड","रूपरेखा दृश्य (Outline View)","हैंडआउट्स (Handouts)","नोट्स पेज"],ans:2,exp:"'हैंडआउट्स' एक विशिष्ट प्रिंट लेआउट है जो मुद्रित कागज की एक शीट पर कई लघु स्लाइड डालता है (उदा., प्रति पृष्ठ 2, 3, 4, 6, या 9 स्लाइड)। '3 स्लाइड' लेआउट विशेष रूप से लोकप्रिय है क्योंकि यह दर्शकों के लिए नोट्स लिखने के लिए विशेष रूप से प्रत्येक स्लाइड के बगल में लाइनें प्रिंट करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which file extension creates a 'PowerPoint Show' that launches directly into full-screen mode when double-clicked, bypassing the editing interface?",opts:[".pptx",".potx",".ppsx",".pptm"],ans:2,exp:"Saving a file as a PowerPoint Show with the '.ppsx' extension completely changes its launch behavior. When opened, it bypasses the standard PowerPoint editing workspace (Normal View) and instantly begins playing the full-screen slide show. This is ideal for distributing finished presentations to viewers."},hi:{q:"कौन सा फ़ाइल एक्सटेंशन एक 'PowerPoint Show' बनाता है जो संपादन इंटरफ़ेस को दरकिनार करते हुए, डबल-क्लिक करने पर सीधे पूर्ण-स्क्रीन मोड में लॉन्च होता है?",opts:[".pptx",".potx",".ppsx",".pptm"],ans:2,exp:"'.ppsx' एक्सटेंशन के साथ फ़ाइल को PowerPoint Show के रूप में सहेजने से इसका लॉन्च व्यवहार पूरी तरह बदल जाता है। खोले जाने पर, यह मानक PowerPoint संपादन कार्यक्षेत्र (सामान्य दृश्य) को बायपास करता है और तुरंत फुल-स्क्रीन स्लाइड शो चलाना शुरू कर देता है। यह दर्शकों को तैयार प्रस्तुतियों को वितरित करने के लिए आदर्श है।"}},
{type:"mcq",diff:"medium",en:{q:"Which view is best utilized for delivering a presentation on a computer screen within a resizable window rather than full screen?",opts:["Slide Sorter View","Reading View","Presenter View","Normal View"],ans:1,exp:"'Reading View' delivers the presentation similarly to Slide Show view, utilizing transitions and animations, but confines it strictly within a standard Windows application frame. This allows the user to run the presentation while simultaneously monitoring the taskbar and multitasking with other open applications."},hi:{q:"पूर्ण स्क्रीन के बजाय एक आकार बदलने योग्य विंडो के भीतर कंप्यूटर स्क्रीन पर प्रस्तुति देने के लिए किस दृश्य (view) का सबसे अच्छा उपयोग किया जाता है?",opts:["स्लाइड सॉर्टर व्यू","रीडिंग व्यू (Reading View)","प्रेजेंटर व्यू","नॉर्मल व्यू"],ans:1,exp:"'रीडिंग व्यू' ट्रांज़िशन और एनिमेशन का उपयोग करते हुए, स्लाइड शो व्यू के समान ही प्रेजेंटेशन डिलीवर करता है, लेकिन इसे मानक Windows एप्लिकेशन फ़्रेम के भीतर सख्ती से सीमित करता है। यह उपयोगकर्ता को एक साथ टास्कबार की निगरानी करने और अन्य खुले अनुप्रयोगों के साथ मल्टीटास्किंग करते हुए प्रस्तुति चलाने की अनुमति देता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which keyboard shortcut permanently groups multiple selected objects into a single unit?",opts:["Ctrl + J","Ctrl + G","Ctrl + M","Ctrl + U"],ans:1,exp:"Selecting multiple shapes or pictures and pressing 'Ctrl + G' executes the 'Group' command. This locks the individual objects together into a single master container. The user can then move, resize, or animate this entire group simultaneously as if it were one single object."},hi:{q:"कौन सा कीबोर्ड शॉर्टकट कई चयनित ऑब्जेक्ट को एक इकाई में स्थायी रूप से समूहित (group) करता है?",opts:["Ctrl + J","Ctrl + G","Ctrl + M","Ctrl + U"],ans:1,exp:"एकाधिक आकृतियों या चित्रों का चयन करने और 'Ctrl + G' दबाने से 'ग्रुप' कमांड निष्पादित होता है। यह अलग-अलग वस्तुओं को एक मास्टर कंटेनर में एक साथ लॉक कर देता है। उपयोगकर्ता तब इस पूरे समूह को एक साथ स्थानांतरित, आकार बदलने या चेतन (animate) करने में सक्षम होता है जैसे कि यह एक ही वस्तु हो।"}},
{type:"mcq",diff:"medium",en:{q:"How do you break a grouped object back into its original individual components?",opts:["Delete the group","Press Ctrl + Shift + G (Ungroup)","Use the Format Painter","Double click the group"],ans:1,exp:"If a user needs to edit one specific piece of a grouped object independently, they must 'Ungroup' it. Pressing 'Ctrl + Shift + G' dissolves the master group container, returning all constituent parts back into completely independent, selectable objects on the slide."},hi:{q:"आप समूहीकृत (grouped) ऑब्जेक्ट को उसके मूल व्यक्तिगत घटकों में वापस कैसे तोड़ते हैं?",opts:["समूह को हटा दें","Ctrl + Shift + G (अनग्रुप) दबाएं","फ़ॉर्मेट पेंटर का उपयोग करें","समूह पर डबल क्लिक करें"],ans:1,exp:"यदि किसी उपयोगकर्ता को समूहीकृत ऑब्जेक्ट के एक विशिष्ट टुकड़े को स्वतंत्र रूप से संपादित करने की आवश्यकता है, तो उन्हें इसे 'अनग्रुप' करना होगा। 'Ctrl + Shift + G' दबाने से मास्टर समूह कंटेनर भंग हो जाता है, सभी घटक भागों को स्लाइड पर पूरी तरह से स्वतंत्र, चयन योग्य वस्तुओं में वापस कर देता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which shortcut key instantly creates an exact clone of the selected slide in the thumbnail pane?",opts:["Ctrl + C","Ctrl + X","Ctrl + D","Ctrl + V"],ans:2,exp:"Pressing 'Ctrl + D' performs the 'Duplicate' command. It bypasses the two-step copy-and-paste process, instantly creating a perfect replica of the selected slide (or object) directly below the original. This is incredibly useful for building sequential slides with minor variations."},hi:{q:"कौन सी शॉर्टकट कुंजी थंबनेल पैन में चयनित स्लाइड का एक सटीक क्लोन तुरंत बनाती है?",opts:["Ctrl + C","Ctrl + X","Ctrl + D","Ctrl + V"],ans:2,exp:"'Ctrl + D' दबाने पर 'डुप्लीकेट' कमांड निष्पादित होता है। यह दो-चरणीय कॉपी-एंड-पेस्ट प्रक्रिया को बायपास करता है, मूल के ठीक नीचे चयनित स्लाइड (या ऑब्जेक्ट) की एक आदर्श प्रतिकृति तुरंत बनाता है। मामूली बदलावों के साथ क्रमिक स्लाइड बनाने के लिए यह अविश्वसनीय रूप से उपयोगी है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the specific purpose of the 'SmartArt' feature in PowerPoint?",opts:["To draw freehand sketches","To visually communicate information through pre-built organizational charts, process flows, and cycles","To run spell check","To insert animated 3D characters"],ans:1,exp:"'SmartArt' is an intelligent graphics tool. It converts standard bulleted lists into high-quality visual diagrams instantly. Users can choose from categories like Hierarchy (for org charts), Process (for timelines), or Cycle (for continuous loops) to visually communicate complex relationships much better than plain text."},hi:{q:"PowerPoint में 'SmartArt' सुविधा का विशिष्ट उद्देश्य क्या है?",opts:["फ्रीहैंड रेखाचित्र खींचने के लिए","पूर्व-निर्मित संगठनात्मक चार्ट, प्रक्रिया प्रवाह और चक्रों के माध्यम से सूचनाओं को दृश्य रूप से संप्रेषित करने के लिए","वर्तनी जांच चलाने के लिए","एनिमेटेड 3D अक्षर डालने के लिए"],ans:1,exp:"'स्मार्टआर्ट' एक बुद्धिमान ग्राफिक्स टूल है। यह मानक बुलेटेड सूचियों को तुरंत उच्च-गुणवत्ता वाले दृश्य आरेखों में परिवर्तित करता है। उपयोगकर्ता सादे पाठ की तुलना में जटिल संबंधों को दृष्टिगत रूप से संवाद करने के लिए पदानुक्रम (ऑर्ग चार्ट के लिए), प्रक्रिया (टाइमलाइन के लिए), या चक्र (निरंतर लूप के लिए) जैसी श्रेणियों में से चुन सकते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which ribbon tab houses the 'Rehearse Timings' feature?",opts:["Review","Insert","Slide Show","Animations"],ans:2,exp:"The 'Rehearse Timings' command is located under the 'Slide Show' tab. It launches a mock presentation equipped with a timer, allowing the presenter to practice their speech. PowerPoint records exactly how long is spent on each slide, which can then be used to automate the final slide progression."},hi:{q:"'रिहर्स टाइमिंग' (Rehearse Timings) फीचर किस रिबन टैब में होता है?",opts:["Review","Insert","Slide Show","Animations"],ans:2,exp:"'रिहर्स टाइमिंग्स' कमांड 'स्लाइड शो' टैब के अंतर्गत स्थित है। यह एक टाइमर से सुसज्जित एक मॉक प्रेजेंटेशन लॉन्च करता है, जिससे प्रस्तुतकर्ता को अपने भाषण का अभ्यास करने की अनुमति मिलती है। PowerPoint ठीक उसी तरह रिकॉर्ड करता है कि प्रत्येक स्लाइड पर कितना समय व्यतीत होता है, जिसका उपयोग तब अंतिम स्लाइड प्रगति को स्वचालित करने के लिए किया जा सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"How can you apply the same formatting to multiple objects consecutively using the Format Painter?",opts:["Single click the Format Painter icon","Double-click the Format Painter icon","Right-click the Format Painter icon","Press Alt while clicking"],ans:1,exp:"Normally, the Format Painter turns off after one use. However, if the user double-clicks the Format Painter icon, it physically locks the tool in the 'on' state. The user can then click continuously on multiple scattered objects or text boxes to apply the formatting repeatedly until they press Esc."},hi:{q:"आप फॉर्मेट पेंटर (Format Painter) का उपयोग करके लगातार कई ऑब्जेक्ट्स में एक ही फॉर्मेटिंग को कैसे लागू कर सकते हैं?",opts:["फॉर्मेट पेंटर आइकन पर सिंगल क्लिक करें","फॉर्मेट पेंटर आइकन पर डबल-क्लिक करें","फॉर्मेट पेंटर आइकन पर राइट-क्लिक करें","क्लिक करते समय Alt दबाएं"],ans:1,exp:"आमतौर पर, फॉर्मेट पेंटर एक उपयोग के बाद बंद हो जाता है। हालाँकि, यदि उपयोगकर्ता फॉर्मेट पेंटर आइकन पर डबल-क्लिक करता है, तो यह भौतिक रूप से उपकरण को 'ऑन' स्थिति में लॉक कर देता है। उपयोगकर्ता तब तक कई बिखरी हुई वस्तुओं या टेक्स्ट बॉक्स पर लगातार क्लिक कर सकता है ताकि बार-बार स्वरूपण लागू किया जा सके जब तक कि वे Esc न दबाएं।"}},
{type:"mcq",diff:"medium",en:{q:"To present tabular data in rows and columns on a slide, which sequence is correct?",opts:["Design > Grid","Home > Columns","Insert > Table","View > Data"],ans:2,exp:"To build a structured grid of data, the user must navigate to the 'Insert' tab and click 'Table'. This opens a visual grid where the user can drag their mouse to define the exact number of rows and columns required before dropping the table onto the active slide."},hi:{q:"स्लाइड पर पंक्तियों और स्तंभों में सारणीबद्ध (tabular) डेटा प्रस्तुत करने के लिए, कौन सा अनुक्रम सही है?",opts:["Design > Grid","Home > Columns","Insert > Table","View > Data"],ans:2,exp:"डेटा का एक संरचित ग्रिड बनाने के लिए, उपयोगकर्ता को 'इंसर्ट' (Insert) टैब पर नेविगेट करना होगा और 'टेबल' पर क्लिक करना होगा। यह एक विज़ुअल ग्रिड खोलता है जहाँ उपयोगकर्ता तालिका को सक्रिय स्लाइड पर छोड़ने से पहले आवश्यक पंक्तियों और स्तंभों की सटीक संख्या को परिभाषित करने के लिए अपने माउस को खींच सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"What does the 'Hide Slide' command achieve?",opts:["It permanently deletes the slide from the file","It makes the slide invisible during the active Slide Show but keeps it intact within the file","It password protects the slide","It turns the slide background black"],ans:1,exp:"The 'Hide Slide' command places a diagonal slash through the slide's number in the thumbnail pane. When the presentation runs in Slide Show mode, PowerPoint seamlessly skips this slide. However, the slide is never deleted and remains fully editable in Normal view, ideal for keeping backup data handy."},hi:{q:"'हाइड स्लाइड' (Hide Slide) कमांड क्या हासिल करता है?",opts:["यह फ़ाइल से स्लाइड को स्थायी रूप से हटा देता है","यह स्लाइड को सक्रिय स्लाइड शो के दौरान अदृश्य बनाता है लेकिन इसे फ़ाइल के भीतर बरकरार रखता है","यह स्लाइड को पासवर्ड से सुरक्षित करता है","यह स्लाइड की पृष्ठभूमि को काला कर देता है"],ans:1,exp:"'हाइड स्लाइड' कमांड थंबनेल पैन में स्लाइड के नंबर के माध्यम से एक विकर्ण (diagonal) स्लैश रखता है। जब प्रेजेंटेशन स्लाइड शो मोड में चलता है, तो PowerPoint निर्बाध रूप से इस स्लाइड को छोड़ देता है। हालाँकि, स्लाइड कभी भी हटाई नहीं जाती है और सामान्य दृश्य में पूरी तरह से संपादन योग्य रहती है, बैकअप डेटा को काम में रखने के लिए आदर्श है।"}},
{type:"mcq",diff:"medium",en:{q:"Which function key instantly initiates the built-in Spell Check tool across the entire presentation?",opts:["F2","F5","F7","F11"],ans:2,exp:"Pressing 'F7' triggers the 'Spelling' dialog box (found under the Review tab). PowerPoint scans every slide's text placeholders and notes pane, halting at words not found in its dictionary to offer suggestions, corrections, or the option to 'Ignore All'."},hi:{q:"कौन सी फ़ंक्शन कुंजी पूरे प्रेजेंटेशन में अंतर्निहित स्पेल चेक (Spell Check) टूल को तुरंत आरंभ करती है?",opts:["F2","F5","F7","F11"],ans:2,exp:"'F7' दबाने से 'स्पेलिंग' डायलॉग बॉक्स ट्रिगर होता है (रिव्यू टैब के अंतर्गत पाया जाता है)। PowerPoint हर स्लाइड के टेक्स्ट प्लेसहोल्डर्स और नोट्स पेन को स्कैन करता है, सुझावों, सुधारों, या 'इग्नोर ऑल' विकल्प की पेशकश करने के लिए अपने शब्दकोश में नहीं पाए जाने वाले शब्दों पर रुकता है।"}},
{type:"mcq",diff:"medium",en:{q:"In PowerPoint animations, what is a 'Motion Path'?",opts:["A trail left by the mouse pointer","A custom geometric track that an object actively follows across the slide space","A type of slide transition","The wiring diagram of the projector"],ans:1,exp:"A 'Motion Path' is an advanced animation type. Instead of just fading in or spinning in place, applying a Motion Path allows the user to draw a literal line, curve, or shape on the slide. Upon triggering, the object physically travels from point A to point B along that exact drawn path."},hi:{q:"PowerPoint एनिमेशन में, 'मोशन पाथ' (Motion Path) क्या है?",opts:["माउस पॉइंटर द्वारा छोड़ा गया एक निशान","एक कस्टम ज्यामितीय ट्रैक जो एक वस्तु स्लाइड अंतरिक्ष में सक्रिय रूप से अनुसरण करती है","एक प्रकार का स्लाइड संक्रमण (transition)","प्रोजेक्टर का वायरिंग आरेख"],ans:1,exp:"एक 'मोशन पाथ' एक उन्नत एनीमेशन प्रकार है। बस लुप्त होने या जगह में कताई करने के बजाय, मोशन पथ को लागू करने से उपयोगकर्ता स्लाइड पर एक शाब्दिक रेखा, वक्र या आकार खींच सकता है। ट्रिगर होने पर, ऑब्जेक्ट शारीरिक रूप से उस सटीक खींचे गए पथ के साथ बिंदु A से बिंदु B तक यात्रा करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following is required to insert a dynamic data Chart (like a pie or bar chart) into PowerPoint?",opts:["Microsoft Word","Microsoft Excel","Adobe Reader","Notepad"],ans:1,exp:"When a user goes to Insert > Chart in PowerPoint, it fundamentally relies on Microsoft Excel's calculation engine. A miniature Excel spreadsheet window opens simultaneously, requiring the user to input the raw data into rows and columns, which seamlessly translates into the visual chart on the PowerPoint slide."},hi:{q:"PowerPoint में डायनामिक डेटा चार्ट (जैसे पाई या बार चार्ट) सम्मिलित करने के लिए निम्नलिखित में से किसकी आवश्यकता होती है?",opts:["Microsoft Word","Microsoft Excel","Adobe Reader","Notepad"],ans:1,exp:"जब कोई उपयोगकर्ता PowerPoint में इन्सर्ट > चार्ट पर जाता है, तो यह मौलिक रूप से Microsoft Excel के गणना इंजन पर निर्भर करता है। एक लघु Excel स्प्रेडशीट विंडो एक साथ खुलती है, जिसमें उपयोगकर्ता को पंक्तियों और स्तंभों में कच्चे डेटा को इनपुट करने की आवश्यकता होती है, जो मूल रूप से PowerPoint स्लाइड पर दृश्य चार्ट में अनुवाद करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Applying a 'Theme' to a presentation modifies which core elements globally?",opts:["Only the background image","Only the font style","Fonts, Colors, and Background graphics simultaneously","Only the slide transitions"],ans:2,exp:"A 'Theme' (found in the Design tab) is a comprehensive design package. Applying one instantly overwrites the presentation's color palette, master font pairs (heading and body), background styles, and graphical placeholder positioning across every single slide, ensuring a professional, cohesive look."},hi:{q:"प्रेजेंटेशन पर 'थीम' (Theme) लागू करने से विश्व स्तर पर किन प्रमुख तत्वों को संशोधित किया जाता है?",opts:["केवल पृष्ठभूमि छवि","केवल फ़ॉन्ट शैली","फ़ॉन्ट, रंग और पृष्ठभूमि ग्राफ़िक्स एक साथ","केवल स्लाइड ट्रांज़िशन"],ans:2,exp:"एक 'थीम' (डिज़ाइन टैब में पाया जाता है) एक व्यापक डिज़ाइन पैकेज है। एक को लागू करने से प्रस्तुति के रंग पैलेट, मास्टर फ़ॉन्ट जोड़े (शीर्षक और शरीर), पृष्ठभूमि शैली, और ग्राफिकल प्लेसहोल्डर स्थिति हर एक स्लाइड पर तुरंत अधिलेखित हो जाती है, जो एक पेशेवर, सामंजस्यपूर्ण रूप सुनिश्चित करती है।"}},
{type:"mcq",diff:"medium",en:{q:"When inserting a video, which Playback option ensures the video repeats continuously until advanced manually?",opts:["Play Full Screen","Loop until Stopped","Rewind after Playing","Hide While Not Playing"],ans:1,exp:"In the Video Tools > Playback ribbon, checking the 'Loop until Stopped' box forces the video to restart seamlessly the millisecond it reaches the end. It will continuously replay this infinite loop while the slide is active, until the presenter clicks to advance to the next slide."},hi:{q:"वीडियो सम्मिलित करते समय, कौन सा प्लेबैक (Playback) विकल्प यह सुनिश्चित करता है कि वीडियो मैन्युअल रूप से उन्नत होने तक लगातार दोहराता रहे?",opts:["फुल स्क्रीन चलाएं (Play Full Screen)","रुकने तक लूप करें (Loop until Stopped)","खेलने के बाद रिवाइंड करें (Rewind after Playing)","न खेलते समय छिपाएं (Hide While Not Playing)"],ans:1,exp:"वीडियो टूल्स > प्लेबैक रिबन में, 'लूप अंटिल स्टॉप्ड' बॉक्स को चेक करने से वीडियो अंत तक पहुंचने वाले मिलीसेकंड को मूल रूप से पुनरारंभ करने के लिए मजबूर करता है। स्लाइड सक्रिय होने पर यह लगातार इस अनंत लूप को रीप्ले करेगा, जब तक कि प्रस्तुतकर्ता अगली स्लाइड पर जाने के लिए क्लिक नहीं करता।"}},
{type:"mcq",diff:"medium",en:{q:"What is the dedicated purpose of the 'Notes Pane' located beneath the main slide?",opts:["To display subtitles for the audience","To store private reference scripts or prompts exclusively for the presenter","To write VBA code","To save the presentation summary"],ans:1,exp:"The 'Notes Pane' provides a hidden workspace where the author can type out full speeches, technical data, or reminders. During the actual presentation via 'Presenter View', these notes are displayed strictly on the speaker's private monitor, while the audience only sees the graphical slide on the projector."},hi:{q:"मुख्य स्लाइड के नीचे स्थित 'नोट्स पैन' (Notes Pane) का समर्पित उद्देश्य क्या है?",opts:["दर्शकों के लिए उपशीर्षक (subtitles) प्रदर्शित करने के लिए","विशेष रूप से प्रस्तुतकर्ता के लिए निजी संदर्भ स्क्रिप्ट या संकेत (prompts) संग्रहीत करने के लिए","VBA कोड लिखने के लिए","प्रस्तुति सारांश सहेजने के लिए"],ans:1,exp:"'नोट्स पैन' एक छिपा हुआ कार्यक्षेत्र प्रदान करता है जहां लेखक पूर्ण भाषण, तकनीकी डेटा या अनुस्मारक टाइप कर सकता है। 'प्रेजेंटर व्यू' के माध्यम से वास्तविक प्रस्तुति के दौरान, ये नोट्स स्पीकर के निजी मॉनिटर पर कड़ाई से प्रदर्शित किए जाते हैं, जबकि दर्शक केवल प्रोजेक्टर पर ग्राफिकल स्लाइड देखते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which Home tab tool modifies the vertical space between lines of text within a placeholder?",opts:["Character Spacing","Text Direction","Line Spacing","Align Text"],ans:2,exp:"The 'Line Spacing' command, found in the Paragraph group on the Home tab, allows users to increase or decrease the physical white space between stacked lines of text. This is critical for improving paragraph readability, allowing adjustments from single spacing to double spacing or specific point values."},hi:{q:"कौन सा होम टैब टूल प्लेसहोल्डर के भीतर टेक्स्ट की पंक्तियों के बीच लंबवत स्थान (vertical space) को संशोधित करता है?",opts:["वर्ण रिक्ति (Character Spacing)","टेक्स्ट दिशा (Text Direction)","लाइन स्पेसिंग (Line Spacing)","टेक्स्ट अलाइन (Align Text)"],ans:2,exp:"होम टैब पर पैराग्राफ समूह में पाया जाने वाला 'लाइन स्पेसिंग' कमांड उपयोगकर्ताओं को टेक्स्ट की स्टैक्ड लाइनों के बीच भौतिक सफेद स्थान को बढ़ाने या घटाने की अनुमति देता है। यह पैराग्राफ पठनीयता में सुधार के लिए महत्वपूर्ण है, एकल रिक्ति से दोहरी रिक्ति या विशिष्ट बिंदु मानों में समायोजन की अनुमति देता है।"}},
{type:"mcq",diff:"medium",en:{q:"How do you combine two adjacent cells in a PowerPoint table into one large cell?",opts:["Split Cells","Merge Cells","Group Cells","Weld Cells"],ans:1,exp:"To combine cells, the user selects two or more contiguous cells, navigates to the Table Tools > Layout tab, and clicks 'Merge Cells'. This physically removes the internal boundary walls, combining them into one single, expansive cell block, which is highly useful for creating wide header rows."},hi:{q:"आप PowerPoint तालिका में दो आसन्न कक्षों को एक बड़े सेल में कैसे जोड़ते हैं?",opts:["स्प्लिट सेल (Split Cells)","मर्ज सेल (Merge Cells)","ग्रुप सेल (Group Cells)","वेल्ड सेल (Weld Cells)"],ans:1,exp:"कोशिकाओं को संयोजित करने के लिए, उपयोगकर्ता दो या दो से अधिक सन्निहित कक्षों का चयन करता है, टेबल टूल्स > लेआउट टैब पर नेविगेट करता है, और 'मर्ज सेल' पर क्लिक करता है। यह भौतिक रूप से आंतरिक सीमा दीवारों को हटा देता है, उन्हें एक एकल, विस्तृत सेल ब्लॉक में जोड़ देता है, जो विस्तृत हेडर पंक्तियाँ बनाने के लिए अत्यधिक उपयोगी है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the function of the 'Eyedropper' tool when coloring shapes or text?",opts:["It deletes color from an object","It applies a random color","It samples and replicates a specific, exact color from anywhere on the screen","It makes the object transparent"],ans:2,exp:"Introduced in newer PowerPoint versions, the 'Eyedropper' tool allows users to click on any pixel on the slide (like a specific color inside a company logo photograph) to sample it. It instantly extracts the exact RGB color code and applies it perfectly to the currently selected text or shape."},hi:{q:"आकृतियों या पाठ को रंगते समय 'आईड्रॉपर' (Eyedropper) टूल का क्या कार्य है?",opts:["यह किसी वस्तु से रंग हटा देता है","यह एक यादृच्छिक रंग लागू करता है","यह स्क्रीन पर कहीं से भी एक विशिष्ट, सटीक रंग का नमूना और प्रतिकृति (replicate) बनाता है","यह वस्तु को पारदर्शी बनाता है"],ans:2,exp:"नए PowerPoint संस्करणों में पेश किया गया, 'आईड्रॉपर' टूल उपयोगकर्ताओं को स्लाइड पर किसी भी पिक्सेल पर क्लिक करने की अनुमति देता है (जैसे कंपनी लोगो फोटोग्राफ के अंदर एक विशिष्ट रंग) इसे नमूना करने के लिए। यह तुरंत सटीक RGB रंग कोड निकालता है और इसे वर्तमान में चयनित पाठ या आकार पर पूरी तरह से लागू करता है।"}},
{type:"mcq",diff:"medium",en:{q:"The 'Text Direction' command in PowerPoint is primarily used to do what?",opts:["Change translation language","Rotate text vertically (90° or 270°) or stack it","Move text to the next slide","Wrap text tightly around a picture"],ans:1,exp:"Unlike Word, PowerPoint does not easily wrap text around complex image contours. The 'Text Direction' button, however, allows users to rotate the actual orientation of the text inside its box. Users can rotate text 90 degrees, 270 degrees, or stack letters vertically, which is highly useful for labeling vertical chart axes."},hi:{q:"PowerPoint में 'टेक्स्ट डायरेक्शन' (Text Direction) कमांड का मुख्य रूप से उपयोग क्या करने के लिए किया जाता है?",opts:["अनुवाद भाषा बदलें","टेक्स्ट को लंबवत (90° या 270°) घुमाएं या स्टैक करें","अगली स्लाइड पर टेक्स्ट ले जाएँ","एक चित्र के चारों ओर टेक्स्ट को कसकर लपेटें (Wrap text)"],ans:1,exp:"Word के विपरीत, PowerPoint जटिल छवि रूपरेखाओं के चारों ओर आसानी से टेक्स्ट नहीं लपेटता है। 'टेक्स्ट डायरेक्शन' बटन, हालांकि, उपयोगकर्ताओं को इसके बॉक्स के अंदर टेक्स्ट के वास्तविक अभिविन्यास को घुमाने की अनुमति देता है। उपयोगकर्ता टेक्स्ट को 90 डिग्री, 270 डिग्री घुमा सकते हैं, या अक्षरों को लंबवत रूप से स्टैक कर सकते हैं, जो ऊर्ध्वाधर चार्ट अक्षों को लेबल करने के लिए अत्यधिक उपयोगी है।"}},
{type:"mcq",diff:"medium",en:{q:"Which view provides the most efficient interface for massively reordering slides by dragging and dropping them?",opts:["Outline View","Reading View","Slide Sorter View","Presenter View"],ans:2,exp:"Because 'Slide Sorter View' shrinks all slides down into a grid of static thumbnails, it visually exposes the macro-structure of the presentation. A user can easily click, drag, and drop single or multiple slides across vast distances in the presentation order instantly without tedious scrolling."},hi:{q:"खींचकर और छोड़कर (dragging and dropping) बड़े पैमाने पर स्लाइडों को फिर से व्यवस्थित करने के लिए कौन सा दृश्य सबसे कुशल इंटरफ़ेस प्रदान करता है?",opts:["आउटलाइन व्यू","रीडिंग व्यू","स्लाइड सॉर्टर व्यू","प्रेजेंटर व्यू"],ans:2,exp:"चूंकि 'स्लाइड सॉर्टर व्यू' सभी स्लाइडों को स्थिर थंबनेल के ग्रिड में सिकोड़ देता है, यह प्रस्तुति की मैक्रो-संरचना को दृष्टिगत रूप से उजागर करता है। एक उपयोगकर्ता बिना थकाऊ स्क्रॉलिंग के तुरंत प्रस्तुति क्रम में विशाल दूरी पर एकल या एकाधिक स्लाइडों को आसानी से क्लिक, ड्रैग और ड्रॉप कर सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is an 'Action Button' in PowerPoint?",opts:["A button on the keyboard","A built-in shape engineered specifically to hold a hyperlink or run a program when clicked","A macro recording tool","A tool to insert equations"],ans:1,exp:"'Action Buttons' are specialized, ready-made shapes found at the bottom of the Shapes gallery. They contain intuitive icons (like arrows or a house). When drawn on a slide, they automatically prompt the 'Action Settings' dialog, allowing the user to easily program them to jump to next/previous slides or open URLs upon clicking."},hi:{q:"PowerPoint में 'एक्शन बटन' (Action Button) क्या है?",opts:["कीबोर्ड पर एक बटन","एक अंतर्निहित आकार जिसे विशेष रूप से हाइपरलिंक रखने या क्लिक किए जाने पर प्रोग्राम चलाने के लिए इंजीनियर किया गया है","एक मैक्रो रिकॉर्डिंग टूल","समीकरण डालने के लिए एक उपकरण"],ans:1,exp:"'एक्शन बटन' विशेष, रेडीमेड आकार हैं जो शेप्स गैलरी के नीचे पाए जाते हैं। इनमें सहज ज्ञान युक्त चिह्न (जैसे तीर या घर) होते हैं। जब एक स्लाइड पर खींचा जाता है, तो वे स्वचालित रूप से 'एक्शन सेटिंग्स' संवाद को संकेत देते हैं, जिससे उपयोगकर्ता को क्लिक करने पर अगली/पिछली स्लाइड पर जाने या URL खोलने के लिए आसानी से प्रोग्राम करने की अनुमति मिलती है।"}},
{type:"mcq",diff:"medium",en:{q:"Which keyboard shortcut immediately opens the 'Insert Hyperlink' dialog box?",opts:["Ctrl + L","Ctrl + H","Ctrl + K","Ctrl + Link"],ans:2,exp:"Selecting an object or text and pressing 'Ctrl + K' instantly opens the Hyperlink dialog. From there, the user can program the text to become a clickable link that navigates to a live webpage, a different specific slide within the same document, an email address, or an external file."},hi:{q:"कौन सा कीबोर्ड शॉर्टकट 'इन्सर्ट हाइपरलिंक' (Insert Hyperlink) डायलॉग बॉक्स तुरंत खोलता है?",opts:["Ctrl + L","Ctrl + H","Ctrl + K","Ctrl + Link"],ans:2,exp:"किसी ऑब्जेक्ट या टेक्स्ट का चयन करना और 'Ctrl + K' दबाने से तुरंत हाइपरलिंक डायलॉग खुल जाता है। वहां से, उपयोगकर्ता टेक्स्ट को क्लिक करने योग्य लिंक बनने के लिए प्रोग्राम कर सकता है जो लाइव वेबपेज, एक ही दस्तावेज़ के भीतर एक अलग विशिष्ट स्लाइड, एक ईमेल पता या एक बाहरी फ़ाइल पर नेविगेट करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which tool allows you to isolate a subject in a photograph by making its background transparent?",opts:["Compress Picture","Remove Background","Color Filter","Artistic Effects"],ans:1,exp:"Under the Picture Tools > Format tab, the 'Remove Background' tool utilizes intelligent edge-detection algorithms to automatically guess the main subject of an image. It highlights the detected background in magenta, which is then erased into transparency, allowing the image subject to float cleanly over the slide background."},hi:{q:"कौन सा उपकरण आपको तस्वीर में किसी विषय की पृष्ठभूमि को पारदर्शी बनाकर उसे अलग करने की अनुमति देता है?",opts:["कंप्रेस पिक्चर (Compress Picture)","रिमूव बैकग्राउंड (Remove Background)","कलर फ़िल्टर (Color Filter)","आर्टिस्टिक इफेक्ट्स (Artistic Effects)"],ans:1,exp:"पिक्चर टूल्स > फ़ॉर्मेट टैब के अंतर्गत, 'रिमूव बैकग्राउंड' टूल स्वचालित रूप से किसी छवि के मुख्य विषय का अनुमान लगाने के लिए बुद्धिमान किनारे-पहचान (edge-detection) एल्गोरिदम का उपयोग करता है। यह मैजेंटा में खोजी गई पृष्ठभूमि को हाइलाइट करता है, जिसे फिर पारदर्शिता में मिटा दिया जाता है, जिससे छवि विषय स्लाइड पृष्ठभूमि पर साफ रूप से तैरने लगता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the function of a 'Custom Slide Show'?",opts:["It generates a random slideshow","It creates a smaller, tailored subset of slides from the main presentation to show to a specific audience","It applies a custom background color","It exports the presentation to a flash drive"],ans:1,exp:"If a 100-slide master presentation contains data for three different departments, the 'Custom Slide Show' feature allows the creator to save specific mini-presentations (e.g., a 20-slide path just for HR). It curates a selective viewing path without deleting any slides or having to maintain multiple separate files."},hi:{q:"'कस्टम स्लाइड शो' (Custom Slide Show) का क्या कार्य है?",opts:["यह एक यादृच्छिक स्लाइड शो उत्पन्न करता है","यह किसी विशिष्ट दर्शक को दिखाने के लिए मुख्य प्रस्तुति से स्लाइडों का एक छोटा, अनुकूलित उपसमूह बनाता है","यह एक कस्टम पृष्ठभूमि रंग लागू करता है","यह प्रस्तुति को फ्लैश ड्राइव में निर्यात (export) करता है"],ans:1,exp:"यदि 100-स्लाइड मास्टर प्रस्तुति में तीन अलग-अलग विभागों के लिए डेटा है, तो 'कस्टम स्लाइड शो' सुविधा निर्माता को विशिष्ट मिनी-प्रस्तुतियों (उदा., केवल HR के लिए 20-स्लाइड पथ) को सहेजने की अनुमति देती है। यह किसी भी स्लाइड को हटाए बिना या कई अलग-अलग फ़ाइलों को बनाए रखने के बिना एक चयनात्मक देखने का मार्ग तैयार करता है।"}},
{type:"tf",diff:"medium",en:{q:"Slide Transitions are used to animate individual text boxes moving onto the screen.",opts:["True","False"],ans:1,exp:"False. Slide Transitions exclusively dictate how the entire slide screen enters and exits the view during a slide change (e.g., Wipe, Fade, Push). Animating individual text boxes or pictures *within* that slide is strictly the function of the 'Animations' tab."},hi:{q:"स्क्रीन पर आने वाले अलग-अलग टेक्स्ट बॉक्स को चेतन (animate) करने के लिए स्लाइड ट्रांज़िशन (Slide Transitions) का उपयोग किया जाता है।",opts:["सही","गलत"],ans:1,exp:"गलत। स्लाइड ट्रांज़िशन विशेष रूप से यह निर्धारित करते हैं कि स्लाइड परिवर्तन (उदा., वाइप, फेड, पुश) के दौरान पूरी स्लाइड स्क्रीन कैसे प्रवेश करती है और दृश्य से बाहर निकलती है। उस स्लाइड के *भीतर* व्यक्तिगत टेक्स्ट बॉक्स या चित्रों को एनिमेट करना सख्ती से 'एनीमेशन' (Animations) टैब का कार्य है।"}},
{type:"tf",diff:"medium",en:{q:"PowerPoint provides a built-in feature to export the entire presentation as a PDF document.",opts:["True","False"],ans:0,exp:"True. Under File > Export (or Save As), users can directly publish the presentation as a PDF. This flattens all fonts, layouts, and graphics into a universally readable, non-editable document, perfect for secure email distribution or printing without worrying about format shifting."},hi:{q:"PowerPoint संपूर्ण प्रस्तुति को PDF दस्तावेज़ के रूप में निर्यात करने के लिए एक अंतर्निहित सुविधा प्रदान करता है।",opts:["सही","गलत"],ans:0,exp:"सही। फ़ाइल > निर्यात (File > Export) (या इस रूप में सहेजें) के अंतर्गत, उपयोगकर्ता सीधे प्रस्तुति को PDF के रूप में प्रकाशित कर सकते हैं। यह सभी फोंट, लेआउट और ग्राफिक्स को सार्वभौमिक रूप से पठनीय, गैर-संपादन योग्य दस्तावेज़ में समतल करता है, जो सुरक्षित ईमेल वितरण या प्रारूप स्थानांतरण की चिंता किए बिना मुद्रण के लिए एकदम सही है।"}},
{type:"mcq",diff:"hard",en:{q:"When inserting a heavy video file, what is the technical difference between 'Inserting' (Embedding) and 'Linking to File'?",opts:["Linking increases the PPT file size significantly","Embedding increases the PPT file size, while Linking keeps the file size small but requires the external video file to remain in the same path location","There is no difference in file size","Embedding causes the video to play in low resolution"],ans:1,exp:"Embedding literally encapsulates the video code inside the .pptx container, causing the PPT file size to balloon immensely, but guaranteeing it plays anywhere. 'Linking' merely creates a shortcut path to the video stored on the hard drive; it keeps the PPT size tiny, but the video will break if the presentation is emailed without the accompanying video file."},hi:{q:"भारी वीडियो फ़ाइल सम्मिलित करते समय, 'इन्सर्टिंग (एम्बेडिंग)' और 'लिंकिंग टू फ़ाइल' (Linking to File) के बीच तकनीकी अंतर क्या है?",opts:["लिंकिंग पीपीटी फ़ाइल का आकार काफी बढ़ा देती है","एम्बेडिंग PPT फ़ाइल का आकार बढ़ा देता है, जबकि लिंकिंग फ़ाइल का आकार छोटा रखता है लेकिन इसके लिए बाहरी वीडियो फ़ाइल को उसी पथ (path) स्थान पर रहने की आवश्यकता होती है","फ़ाइल आकार में कोई अंतर नहीं है","एम्बेडिंग के कारण वीडियो कम रिज़ॉल्यूशन में चलता है"],ans:1,exp:"एम्बेडिंग वस्तुतः .pptx कंटेनर के अंदर वीडियो कोड को समाहित करता है, जिससे पीपीटी फ़ाइल का आकार काफी बढ़ जाता है, लेकिन यह गारंटी देता है कि यह कहीं भी चलता है। 'लिंकिंग' केवल हार्ड ड्राइव पर संग्रहीत वीडियो के लिए एक शॉर्टकट पथ (path) बनाता है; यह PPT आकार को छोटा रखता है, लेकिन यदि साथ वाले वीडियो फ़ाइल के बिना प्रस्तुति को ईमेल किया जाता है तो वीडियो टूट जाएगा (break हो जाएगा)।"}},
{type:"mcq",diff:"hard",en:{q:"In the Advanced Animations pane, what does setting a 'Trigger' accomplish?",opts:["It forces the animation to loop endlessly","It causes a specific animation to run only when the presenter actively clicks on a designated shape or object on the slide","It deletes the animation","It triggers an alarm sound"],ans:1,exp:"A 'Trigger' transforms a passive animation into an interactive element. Instead of an animation running automatically in a linear sequence, a Trigger ensures that the animation is completely dormant until the presenter explicitly uses their mouse to click a specific designated object (like a 'Start' button) during the show."},hi:{q:"एडवांस्ड एनिमेशन पैन (Advanced Animations pane) में, 'ट्रिगर' (Trigger) सेट करने से क्या हासिल होता है?",opts:["यह एनीमेशन को अंतहीन लूप के लिए मजबूर करता है","यह एक विशिष्ट एनीमेशन को केवल तभी चलाने का कारण बनता है जब प्रस्तुतकर्ता सक्रिय रूप से स्लाइड पर निर्दिष्ट आकार या वस्तु पर क्लिक करता है","यह एनीमेशन हटाता है","यह एक अलार्म ध्वनि को ट्रिगर करता है"],ans:1,exp:"एक 'ट्रिगर' एक निष्क्रिय एनीमेशन को एक इंटरैक्टिव तत्व में बदल देता है। एक रैखिक अनुक्रम में स्वचालित रूप से चलने वाले एनीमेशन के बजाय, एक ट्रिगर यह सुनिश्चित करता है कि एनीमेशन पूरी तरह से निष्क्रिय है जब तक कि प्रस्तुतकर्ता शो के दौरान एक विशिष्ट नामित ऑब्जेक्ट (जैसे 'स्टार्ट' बटन) पर क्लिक करने के लिए स्पष्ट रूप से अपने माउस का उपयोग नहीं करता है।"}},
{type:"mcq",diff:"hard",en:{q:"If you configure a presentation using 'Set Up Slide Show -> Browsed at a kiosk (full screen)', what major restriction is placed on the slide show?",opts:["It disables all video playback","It removes all colors making it black and white","It disables standard mouse clicks or keyboard strokes to advance slides, requiring programmed Hyperlinks or Action Buttons for navigation","It mutes the audio track"],ans:2,exp:"Kiosk mode is designed for unattended displays, like trade show booths. By enabling 'Browsed at a kiosk', PowerPoint deliberately locks the interface, ignoring accidental mouse clicks or keyboard presses that would normally advance the slide. Navigation is strictly limited to pre-programmed interactive Action Buttons or automatic timings."},hi:{q:"यदि आप 'सेट अप स्लाइड शो -> कियोस्क पर ब्राउज़ किया गया (पूर्ण स्क्रीन)' का उपयोग करके कोई प्रेजेंटेशन कॉन्फ़िगर करते हैं, तो स्लाइड शो पर क्या प्रमुख प्रतिबंध लगाया गया है?",opts:["यह सभी वीडियो प्लेबैक को अक्षम करता है","यह काले और सफेद बनाने वाले सभी रंगों को हटा देता है","यह स्लाइड को आगे बढ़ाने के लिए मानक माउस क्लिक या कीबोर्ड स्ट्रोक को अक्षम करता है, नेविगेशन के लिए प्रोग्राम किए गए हाइपरलिंक या एक्शन बटन की आवश्यकता होती है","यह ऑडियो ट्रैक को म्यूट करता है"],ans:2,exp:"कियोस्क मोड (Kiosk mode) व्यापार शो बूथ (trade show booths) जैसे अप्राप्य (unattended) डिस्प्ले के लिए डिज़ाइन किया गया है। 'कियोस्क पर ब्राउज़ किया गया' सक्षम करके, PowerPoint जानबूझकर इंटरफ़ेस को लॉक कर देता है, आकस्मिक माउस क्लिक या कीबोर्ड प्रेस को अनदेखा कर देता है जो सामान्य रूप से स्लाइड को आगे बढ़ाते हैं। नेविगेशन कड़ाई से पूर्व-प्रोग्राम किए गए इंटरैक्टिव एक्शन बटन या स्वचालित समय तक सीमित है।"}},
{type:"mcq",diff:"hard",en:{q:"What is the absolute maximum number of columns you can create in a standard PowerPoint table?",opts:["10","25","75","100"],ans:2,exp:"Due to specific engine limitations and practical aesthetic constraints regarding slide sizes, Microsoft PowerPoint restricts a single table object to a strict maximum of 75 columns and 75 rows. Attempting to insert 76 columns via the Insert Table dialog will throw an explicit limitation error."},hi:{q:"आप एक मानक PowerPoint तालिका में अधिकतम कितने कॉलम बना सकते हैं?",opts:["10","25","75","100"],ans:2,exp:"विशिष्ट इंजन सीमाओं और स्लाइड आकारों के संबंध में व्यावहारिक सौंदर्य बाधाओं के कारण, Microsoft PowerPoint एकल तालिका ऑब्जेक्ट को अधिकतम 75 कॉलम और 75 पंक्तियों तक सीमित करता है। इन्सर्ट टेबल डायलॉग के माध्यम से 76 कॉलम सम्मिलित करने का प्रयास करने पर एक स्पष्ट सीमा त्रुटि (limitation error) उत्पन्न होगी।"}},
{type:"mcq",diff:"hard",en:{q:"Which of the following shortcuts instantly opens the complex 'Font' formatting dialog box in PowerPoint?",opts:["Ctrl + F","Ctrl + T","Ctrl + H","Ctrl + W"],ans:1,exp:"While Ctrl+B or Ctrl+I provide quick access, pressing 'Ctrl + T' (or Ctrl+Shift+F) instantly summons the comprehensive Font dialog box. This advanced menu gives the user deep granular control over complex typographical settings like character spacing, precise kerning, superscript/subscript offsets, and shadow formatting."},hi:{q:"निम्नलिखित में से कौन सा शॉर्टकट PowerPoint में जटिल 'फ़ॉन्ट' (Font) स्वरूपण संवाद बॉक्स (dialog box) तुरंत खोलता है?",opts:["Ctrl + F","Ctrl + T","Ctrl + H","Ctrl + W"],ans:1,exp:"जबकि Ctrl+B या Ctrl+I त्वरित पहुँच प्रदान करते हैं, 'Ctrl + T' (या Ctrl+Shift+F) दबाने पर व्यापक फ़ॉन्ट संवाद बॉक्स तुरंत आ जाता है। यह उन्नत मेनू उपयोगकर्ता को जटिल मुद्रण संबंधी सेटिंग्स जैसे कैरेक्टर स्पेसिंग, सटीक केर्निंग (kerning), सुपरस्क्रिप्ट/सबस्क्रिप्ट ऑफ़सेट और शैडो फ़ॉर्मेटिंग पर गहरा दानेदार (granular) नियंत्रण देता है।"}},
{type:"mcq",diff:"hard",en:{q:"To drastically reduce the file size of a presentation containing heavy video files without deleting them, which File > Info command should be used?",opts:["Optimize Compatibility","Compress Media","Inspect Document","Encrypt with Password"],ans:1,exp:"The 'Compress Media' tool aggressively down-samples embedded audio and video files. It transcodes the media, lowering the resolution (e.g., from 1080p to 720p or 480p) and dropping frames to vastly reduce the overall megabyte footprint of the .pptx file, making it suitable for email distribution."},hi:{q:"भारी वीडियो फ़ाइलों वाले प्रेजेंटेशन के फ़ाइल आकार को उन्हें हटाए बिना भारी रूप से कम करने के लिए, किस 'फ़ाइल > जानकारी' (File > Info) कमांड का उपयोग किया जाना चाहिए?",opts:["संगतता अनुकूलित करें (Optimize Compatibility)","संपीड़ित मीडिया (Compress Media)","दस्तावेज़ का निरीक्षण करें (Inspect Document)","पासवर्ड के साथ एन्क्रिप्ट करें (Encrypt with Password)"],ans:1,exp:"'कंप्रेस मीडिया' टूल एम्बेडेड ऑडियो और वीडियो फ़ाइलों को आक्रामक रूप से डाउन-सैंपल करता है। यह रिज़ॉल्यूशन को कम करते हुए (उदा., 1080p से 720p या 480p तक) मीडिया को ट्रांसकोड करता है और .pptx फ़ाइल के समग्र मेगाबाइट फुटप्रिंट को कम करने के लिए फ़्रेम को छोड़ता है, जिससे यह ईमेल वितरण के लिए उपयुक्त हो जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"When sharing a .pptx file, how can a user guarantee that custom downloaded typography is displayed correctly on a different computer that does not have those fonts installed?",opts:["Save as PDF","Enable 'Embed fonts in the file' under Save Options","Run the Accessibility Checker","Save the file as a Macro"],ans:1,exp:"To prevent PowerPoint from automatically substituting missing fonts with standard ones (like Calibri), the author must navigate to File > Options > Save and check 'Embed fonts in the file'. This literally packages the TrueType font architecture inside the .pptx container, ensuring exact visual fidelity on any machine."},hi:{q:".pptx फ़ाइल साझा करते समय, कोई उपयोगकर्ता यह कैसे गारंटी दे सकता है कि कस्टम डाउनलोड की गई टाइपोग्राफी (typography) किसी भिन्न कंप्यूटर पर सही ढंग से प्रदर्शित होती है जिसमें वे फ़ॉन्ट स्थापित नहीं हैं?",opts:["PDF के रूप में सहेजें","सेव ऑप्शंस के तहत 'फ़ाइल में फ़ॉन्ट एम्बेड करें' सक्षम करें","अभिगम्यता परीक्षक (Accessibility Checker) चलाएँ","फ़ाइल को मैक्रो के रूप में सहेजें"],ans:1,exp:"PowerPoint को मानक वाले (जैसे कैलीब्री) के साथ गायब फोंट को स्वचालित रूप से प्रतिस्थापित करने से रोकने के लिए, लेखक को फ़ाइल> विकल्प> सहेजें (File > Options > Save) पर नेविगेट करना होगा और 'फ़ाइल में फ़ॉन्ट एम्बेड करें' (Embed fonts in the file) की जांच करनी होगी। यह वस्तुतः .pptx कंटेनर के अंदर ट्रू टाइप (TrueType) फ़ॉन्ट आर्किटेक्चर को पैकेज करता है, जो किसी भी मशीन पर सटीक दृश्य निष्ठा सुनिश्चित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In complex slides containing dozens of overlapping shapes, which tool provides a layered list to easily hide, show, or rename individual objects?",opts:["Slide Master","Animation Pane","Selection Pane","Notes Master"],ans:2,exp:"The 'Selection Pane' (Home > Select > Selection Pane) is an advanced layout management tool. It exposes every single object on the slide in a hierarchical list (similar to layers in Photoshop). Users can toggle the eyeball icon to temporarily hide top layers, allowing them to easily edit heavily obscured objects underneath."},hi:{q:"दर्जनों अतिव्यापी आकृतियों (overlapping shapes) वाली जटिल स्लाइडों में, कौन सा उपकरण अलग-अलग वस्तुओं को आसानी से छिपाने, दिखाने या नाम बदलने के लिए एक स्तरित (layered) सूची प्रदान करता है?",opts:["स्लाइड मास्टर","एनिमेशन पैन","चयन पैन (Selection Pane)","नोट्स मास्टर"],ans:2,exp:"'सेलेक्शन पैन' (होम > सेलेक्ट > सिलेक्शन पैन) एक उन्नत लेआउट प्रबंधन टूल है। यह एक पदानुक्रमित सूची (फ़ोटोशॉप में परतों के समान) में स्लाइड पर हर एक वस्तु को उजागर करता है। उपयोगकर्ता शीर्ष परतों को अस्थायी रूप से छिपाने के लिए आईबॉल (eyeball) आइकन को टॉगल कर सकते हैं, जिससे वे आसानी से नीचे भारी अस्पष्ट वस्तुओं को संपादित कर सकते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What unique action does the 'Morph' transition perform that standard transitions do not?",opts:["It plays an audio track across multiple slides","It smoothly animates the movement, sizing, and color changes of identical objects transitioning from one slide to the next","It generates a 3D cube effect","It embeds a video in the background"],ans:1,exp:"Introduced in recent versions of Office, the 'Morph' transition mathematically calculates the position, scale, and rotation of identically named objects on Slide A and Slide B. When transitioning, instead of a simple fade, it seamlessly animates the object physically gliding and morphing into its new state on the second slide."},hi:{q:"'मॉर्फ' (Morph) ट्रांज़िशन कौन सी अनूठी क्रिया करता है जो मानक ट्रांज़िशन नहीं करते हैं?",opts:["यह कई स्लाइडों पर एक ऑडियो ट्रैक चलाता है","यह एक स्लाइड से दूसरी स्लाइड में जाने वाली समान वस्तुओं की गति, आकार और रंग परिवर्तन को सुचारू रूप से एनिमेट करता है","यह एक 3D क्यूब प्रभाव उत्पन्न करता है","यह पृष्ठभूमि में एक वीडियो एम्बेड करता है"],ans:1,exp:"Office के हाल के संस्करणों में पेश किया गया, 'मॉर्फ' ट्रांज़िशन गणितीय रूप से स्लाइड A और स्लाइड B पर समान रूप से नामित वस्तुओं की स्थिति, पैमाने और रोटेशन की गणना करता है। संक्रमण के दौरान, एक साधारण फीके के बजाय, यह निर्बाध रूप से भौतिक रूप से सरकने और दूसरी स्लाइड पर अपने नए राज्य में मॉर्फिंग करने वाली वस्तु को एनिमेट करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What is 'Branching' in the context of a PowerPoint presentation?",opts:["Splitting text into multiple columns","Using Action Buttons or Hyperlinks to create a non-linear, choose-your-own-path navigation structure through the slides","Adding tree graphics to the background","Exporting slides into multiple separate files"],ans:1,exp:"'Branching' transforms a linear slide deck into an interactive application. By utilizing extensive Hyperlinks and Action Buttons on menu slides, the presenter can break the standard sequential order. They can click specific buttons to jump wildly to different contextual sections ('branches') depending on audience feedback, and then return to the menu."},hi:{q:"PowerPoint प्रस्तुति के संदर्भ में 'ब्रांचिंग' (Branching) क्या है?",opts:["टेक्स्ट को कई कॉलम में विभाजित करना","स्लाइड के माध्यम से एक गैर-रैखिक, अपने-स्वयं-पथ (choose-your-own-path) नेविगेशन संरचना बनाने के लिए एक्शन बटन या हाइपरलिंक का उपयोग करना","पृष्ठभूमि में ट्री ग्राफ़िक्स जोड़ना","स्लाइड को कई अलग-अलग फ़ाइलों में निर्यात करना"],ans:1,exp:"'ब्रांचिंग' एक रैखिक स्लाइड डेक को एक इंटरैक्टिव एप्लिकेशन में बदल देता है। मेनू स्लाइड पर व्यापक हाइपरलिंक और एक्शन बटन का उपयोग करके, प्रस्तुतकर्ता मानक अनुक्रमिक क्रम को तोड़ सकता है। वे दर्शकों की प्रतिक्रिया के आधार पर विभिन्न प्रासंगिक वर्गों ('शाखाओं') पर बेतहाशा कूदने के लिए विशिष्ट बटन पर क्लिक कर सकते हैं, और फिर मेनू पर लौट सकते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Which file format must be used if the presentation contains automated Visual Basic (VBA) macro scripts?",opts:[".pptx",".potx",".pptm",".ppsx"],ans:2,exp:"Due to stringent security architectures designed to combat malicious scripts, a standard '.pptx' file absolutely cannot store executable macros. The user is forced to save the presentation specifically as a Macro-Enabled Presentation using the '.pptm' extension to preserve and execute the VBA code."},hi:{q:"यदि प्रस्तुति में स्वचालित विज़ुअल बेसिक (VBA) मैक्रो स्क्रिप्ट हैं तो किस फ़ाइल स्वरूप का उपयोग किया जाना चाहिए?",opts:[".pptx",".potx",".pptm",".ppsx"],ans:2,exp:"दुर्भावनापूर्ण स्क्रिप्ट का मुकाबला करने के लिए डिज़ाइन किए गए कड़े सुरक्षा आर्किटेक्चर के कारण, एक मानक '.pptx' फ़ाइल बिल्कुल निष्पादन योग्य मैक्रोज़ को संग्रहीत नहीं कर सकती है। VBA कोड को संरक्षित करने और निष्पादित करने के लिए उपयोगकर्ता को '.pptm' एक्सटेंशन का उपयोग करके विशेष रूप से मैक्रो-सक्षम प्रस्तुति (Macro-Enabled Presentation) के रूप में प्रस्तुति को सहेजने के लिए मजबूर किया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which keyboard shortcut immediately demotes a bulleted list item (pushes it inward to create a sub-point)?",opts:["Enter","Spacebar","Tab","Ctrl + D"],ans:2,exp:"While editing a bulleted list, placing the cursor at the front of a line and pressing 'Tab' demotes the item. It physically pushes the text to the right, changes the bullet icon style, and alters the text size according to the Slide Master rules to create a lower-level sub-point. (Shift+Tab promotes it)."},hi:{q:"कौन सा कीबोर्ड शॉर्टकट बुलेटेड सूची आइटम को तुरंत पदावनत (demotes) करता है (उप-बिंदु (sub-point) बनाने के लिए इसे अंदर की ओर धकेलता है)?",opts:["Enter","Spacebar","Tab","Ctrl + D"],ans:2,exp:"बुलेटेड सूची को संपादित करते समय, कर्सर को लाइन के सामने रखने और 'टैब' (Tab) दबाने से आइटम का स्तर गिर जाता है। यह शारीरिक रूप से पाठ को दाईं ओर धकेलता है, बुलेट आइकन शैली को बदलता है, और एक निचले स्तर का उप-बिंदु बनाने के लिए स्लाइड मास्टर नियमों के अनुसार पाठ का आकार बदलता है। (Shift+Tab इसे बढ़ावा (promotes) देता है)।"}},
{type:"mcq",diff:"hard",en:{q:"What is the inverse shortcut of Tab used to PROMOTE a bullet point (push it leftwards)?",opts:["Ctrl + Tab","Shift + Tab","Alt + Tab","Windows + Tab"],ans:1,exp:"If a user has deeply nested a bullet point and wishes to move it back up the hierarchy to a primary point, they must position the cursor at the text's start and press 'Shift + Tab'. This promotes the list item, pushing it leftward to the parent indent level."},hi:{q:"एक बुलेट बिंदु को बढ़ावा (PROMOTE) देने (इसे बाईं ओर धकेलने) के लिए उपयोग किए जाने वाले टैब (Tab) का व्युत्क्रम (inverse) शॉर्टकट क्या है?",opts:["Ctrl + Tab","Shift + Tab","Alt + Tab","Windows + Tab"],ans:1,exp:"यदि किसी उपयोगकर्ता ने गहराई से नेस्टेड बुलेट पॉइंट रखा है और इसे पदानुक्रम में प्राथमिक बिंदु (primary point) पर वापस ले जाना चाहता है, तो उन्हें कर्सर को टेक्स्ट की शुरुआत में रखना होगा और 'Shift + Tab' दबाना होगा। यह सूची आइटम को बढ़ावा देता है, इसे पैरेंट इंडेंट स्तर (parent indent level) पर बाईं ओर धकेलता है।"}},
{type:"mcq",diff:"hard",en:{q:"If you have painstakingly created a highly complex custom animation path on one shape, which tool allows you to instantly copy that exact animation sequence to another shape?",opts:["Format Painter","Animation Painter","Macro Builder","Action Button"],ans:1,exp:"Introduced to save immense programming time, the 'Animation Painter' (located in the Advanced Animation group) functions exactly like the Format Painter, but for motion. It copies the entire stack of entrance, emphasis, exit, and motion path logic from the source object and applies it perfectly to the target object."},hi:{q:"यदि आपने एक आकार पर एक अत्यधिक जटिल कस्टम एनीमेशन पथ (custom animation path) बनाया है, तो कौन सा टूल आपको उस सटीक एनीमेशन अनुक्रम (animation sequence) को दूसरे आकार में तुरंत कॉपी करने की अनुमति देता है?",opts:["फॉर्मेट पेंटर (Format Painter)","एनिमेशन पेंटर (Animation Painter)","मैक्रो बिल्डर (Macro Builder)","एक्शन बटन (Action Button)"],ans:1,exp:"अत्यधिक प्रोग्रामिंग समय बचाने के लिए पेश किया गया, 'एनिमेशन पेंटर' (उन्नत एनिमेशन समूह में स्थित) बिल्कुल फॉर्मेट पेंटर की तरह काम करता है, लेकिन गति के लिए। यह स्रोत वस्तु से प्रवेश, जोर, निकास और गति पथ तर्क के पूरे स्टैक की प्रतिलिपि बनाता है और इसे लक्ष्य वस्तु पर पूरी तरह से लागू करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which audio file format natively inserted into PowerPoint is typically completely uncompressed, resulting in the highest audio fidelity but massively inflating the presentation file size?",opts:[".mp3",".wma",".wav",".m4a"],ans:2,exp:"The '.wav' (Waveform Audio File) format is the standard Microsoft uncompressed audio wrapper. Because it lacks lossy compression algorithms (unlike .mp3), a .wav file provides perfect CD-quality sound but requires enormous amounts of megabytes, which can cause severe lag or freezing when embedded in large presentations."},hi:{q:"PowerPoint में मूल रूप से डाला गया कौन सा ऑडियो फ़ाइल स्वरूप आमतौर पर पूरी तरह से असम्पीडित (uncompressed) होता है, जिसके परिणामस्वरूप उच्चतम ऑडियो निष्ठा होती है लेकिन प्रस्तुति फ़ाइल का आकार बड़े पैमाने पर बढ़ जाता है?",opts:[".mp3",".wma",".wav",".m4a"],ans:2,exp:"'.wav' (Waveform Audio File) प्रारूप मानक Microsoft असम्पीडित ऑडियो रैपर है। क्योंकि इसमें हानिपूर्ण संपीड़न एल्गोरिदम (lossy compression algorithms) का अभाव है (.mp3 के विपरीत), एक .wav फ़ाइल सही सीडी-गुणवत्ता ध्वनि प्रदान करती है, लेकिन इसके लिए भारी मात्रा में मेगाबाइट की आवश्यकता होती है, जो बड़ी प्रस्तुतियों में एम्बेडेड होने पर गंभीर अंतराल या ठंड का कारण बन सकती है।"}},
{type:"mcq",diff:"hard",en:{q:"Without using external tools, how does the built-in 'Screenshot' feature in PowerPoint's Insert tab behave?",opts:["It turns on the webcam","It automatically populates a gallery showing live thumbnails of all other currently non-minimized windows open on your desktop for instant insertion","It downloads screenshots from Google","It takes a picture of the PowerPoint ribbon"],ans:1,exp:"The native 'Screenshot' tool is highly integrated with the Windows OS. Clicking it reveals a visual gallery of all active, un-minimized software windows currently running behind PowerPoint. Clicking a thumbnail instantly pastes a full-resolution capture of that specific window directly onto the active slide."},hi:{q:"बाहरी उपकरणों का उपयोग किए बिना, PowerPoint के इन्सर्ट टैब में अंतर्निहित 'स्क्रीनशॉट' (Screenshot) सुविधा कैसे व्यवहार करती है?",opts:["यह वेबकैम चालू करता है","यह स्वचालित रूप से तत्काल प्रविष्टि के लिए आपके डेस्कटॉप पर खुले अन्य सभी वर्तमान में गैर-न्यूनतम विंडो के लाइव थंबनेल दिखाते हुए एक गैलरी पॉप्युलेट करता है","यह Google से स्क्रीनशॉट डाउनलोड करता है","यह PowerPoint रिबन की तस्वीर लेता है"],ans:1,exp:"मूल 'स्क्रीनशॉट' टूल Windows OS के साथ अत्यधिक एकीकृत है। इसे क्लिक करने से वर्तमान में PowerPoint के पीछे चल रहे सभी सक्रिय, अन-मिनिमाइज्ड (un-minimized) सॉफ़्टवेयर विंडो की एक दृश्य गैलरी का पता चलता है। थंबनेल पर क्लिक करने से उस विशिष्ट विंडो का पूर्ण-रिज़ॉल्यूशन कैप्चर सीधे सक्रिय स्लाइड पर तुरंत पेस्ट हो जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"When running a dual-monitor setup, what is the specific advantage of enabling 'Presenter View'?",opts:["It stretches one slide across both monitors","It shows the audience the presenter's private speaker notes","It displays the full-screen slide to the audience on the projector, while exclusively showing the speaker notes, timer, and upcoming slide previews on the presenter's laptop","It disables animations to save battery"],ans:2,exp:"'Presenter View' is an absolute necessity for professional delivery. It splits the video output. The audience monitor receives the clean, full-screen graphical slide. Concurrently, the speaker's laptop renders a complex dashboard showing the current slide, the elapsed timer, private typed notes, and a preview of the next animation or slide."},hi:{q:"दोहरे मॉनिटर (dual-monitor) सेटअप को चलाते समय, 'प्रेजेंटर व्यू' (Presenter View) को सक्षम करने का विशिष्ट लाभ क्या है?",opts:["यह एक स्लाइड को दोनों मॉनिटरों तक फैलाता है","यह दर्शकों को प्रस्तुतकर्ता के निजी स्पीकर नोट्स दिखाता है","यह दर्शकों को प्रोजेक्टर पर फुल-स्क्रीन स्लाइड प्रदर्शित करता है, जबकि विशेष रूप से स्पीकर नोट्स, टाइमर और आगामी स्लाइड प्रीव्यू प्रस्तुतकर्ता के लैपटॉप पर दिखाता है","यह बैटरी बचाने के लिए एनिमेशन को निष्क्रिय कर देता है"],ans:2,exp:"पेशेवर वितरण के लिए 'प्रेजेंटर व्यू' एक पूर्ण आवश्यकता है। यह वीडियो आउटपुट को विभाजित करता है। दर्शक मॉनिटर को स्वच्छ, पूर्ण-स्क्रीन ग्राफिकल स्लाइड प्राप्त होती है। इसके साथ ही, स्पीकर का लैपटॉप वर्तमान स्लाइड, बीता हुआ टाइमर, निजी टाइप किए गए नोट्स और अगले एनीमेशन या स्लाइड का पूर्वावलोकन दिखाते हुए एक जटिल डैशबोर्ड प्रस्तुत करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What massive data array does the 'Record Slide Show' feature capture permanently into the file?",opts:["Only audio narrations","Strictly the timestamps of when slides are changed","The combined total of voice narration, precise slide and animation timings, laser pointer movements, and digital ink gestures","A video recording of the audience"],ans:2,exp:"'Record Slide Show' creates a highly complex, self-running multimedia package. It meticulously tracks the millisecond the presenter advances animations, records synchronized microphone audio per slide, and maps the coordinate data of on-screen laser pointer and pen annotations, saving it all intrinsically within the .pptx container."},hi:{q:"'रिकॉर्ड स्लाइड शो' (Record Slide Show) सुविधा फ़ाइल में स्थायी रूप से किस विशाल डेटा को कैप्चर करती है?",opts:["केवल ऑडियो कथन (narrations)","सख्ती से जब स्लाइड को बदला जाता है तो टाइमस्टैम्प","ध्वनि कथन का संयुक्त कुल, सटीक स्लाइड और एनीमेशन समय, लेजर पॉइंटर आंदोलन, और डिजिटल स्याही इशारों","दर्शकों की एक वीडियो रिकॉर्डिंग"],ans:2,exp:"'रिकॉर्ड स्लाइड शो' एक अत्यधिक जटिल, स्व-संचालित मल्टीमीडिया पैकेज बनाता है। यह सूक्ष्मता से उस मिलीसेकंड को ट्रैक करता है जब प्रस्तुतकर्ता एनिमेशन को आगे बढ़ाता है, प्रति स्लाइड सिंक्रनाइज़ माइक्रोफ़ोन ऑडियो रिकॉर्ड करता है, और ऑन-स्क्रीन लेजर पॉइंटर और पेन एनोटेशन के समन्वय डेटा को मैप करता है, इसे .pptx कंटेनर के भीतर आंतरिक रूप से सहेजता है।"}},
{type:"mcq",diff:"hard",en:{q:"What protection mechanism does the 'Mark as Final' command actually provide?",opts:["Military-grade 256-bit AES encryption","It permanently locks the file so no human can ever edit it again","It simply turns the file into a strict 'Read-Only' state to politely discourage editing, but any user can easily bypass it by clicking 'Edit Anyway'","It deletes all macros from the file"],ans:2,exp:"'Mark as Final' is an administrative tagging tool, not a cryptographic security measure. It sets the file's metadata to read-only, collapsing the Ribbon UI upon opening and displaying a yellow warning bar. However, it offers absolutely zero hard security; any user can simply click 'Edit Anyway' on the warning bar to unlock it completely."},hi:{q:"'मार्क एज़ फ़ाइनल' (Mark as Final) कमांड वास्तव में क्या सुरक्षा तंत्र प्रदान करता है?",opts:["सैन्य-ग्रेड 256-बिट एईएस एन्क्रिप्शन","यह फ़ाइल को स्थायी रूप से लॉक कर देता है ताकि कोई भी इंसान इसे फिर कभी संपादित न कर सके","यह संपादन को विनम्रता से हतोत्साहित करने के लिए फ़ाइल को सख्त 'केवल-पढ़ने के लिए' (Read-Only) स्थिति में बदल देता है, लेकिन कोई भी उपयोगकर्ता 'वैसे भी संपादित करें' (Edit Anyway) पर क्लिक करके आसानी से इसे बायपास कर सकता है","यह फ़ाइल से सभी मैक्रोज़ को हटा देता है"],ans:2,exp:"'मार्क एज़ फ़ाइनल' एक प्रशासनिक टैगिंग टूल है, कोई क्रिप्टोग्राफ़िक सुरक्षा उपाय नहीं है। यह फ़ाइल के मेटाडेटा को केवल-पढ़ने के लिए सेट करता है, खोलने पर रिबन UI को संक्षिप्त करता है और एक पीली चेतावनी पट्टी प्रदर्शित करता है। हालाँकि, यह बिल्कुल शून्य कठिन सुरक्षा प्रदान करता है; कोई भी उपयोगकर्ता इसे पूरी तरह से अनलॉक करने के लिए चेतावनी बार पर केवल 'एडिट एनीवे' पर क्लिक कर सकता है।"}},
{type:"mcq",diff:"hard",en:{q:"To truly secure a highly confidential presentation against unauthorized opening, which exact security feature must be applied?",opts:["Mark as Final","Add a Digital Signature","Encrypt with Password","Restrict Access"],ans:2,exp:"To apply robust mathematical security, the user must select File > Info > Protect Presentation > 'Encrypt with Password'. This hashes the document using strong AES encryption algorithms. If the password is lost, the underlying XML data is completely unrecoverable, providing true security against unauthorized viewing."},hi:{q:"अनधिकृत उद्घाटन (unauthorized opening) के खिलाफ एक अत्यधिक गोपनीय प्रस्तुति को वास्तव में सुरक्षित करने के लिए, कौन सी सटीक सुरक्षा सुविधा लागू की जानी चाहिए?",opts:["अंतिम के रूप में चिह्नित करें (Mark as Final)","एक डिजिटल हस्ताक्षर जोड़ें (Add a Digital Signature)","पासवर्ड से एन्क्रिप्ट करें (Encrypt with Password)","पहुंच प्रतिबंधित करें (Restrict Access)"],ans:2,exp:"मजबूत गणितीय सुरक्षा लागू करने के लिए, उपयोगकर्ता को फ़ाइल > जानकारी > प्रस्तुति सुरक्षित करें > 'पासवर्ड के साथ एन्क्रिप्ट करें' (File > Info > Protect Presentation > 'Encrypt with Password') का चयन करना होगा। यह मजबूत एईएस एन्क्रिप्शन एल्गोरिदम का उपयोग करके दस्तावेज़ को हैश (hash) करता है। यदि पासवर्ड खो जाता है, तो अंतर्निहित XML डेटा पूरी तरह से अप्राप्य है, जो अनधिकृत देखने के खिलाफ सच्ची सुरक्षा प्रदान करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In older PowerPoint versions (2010 and prior), the default Slide Size aspect ratio was 4:3. What is the modern default Slide Size aspect ratio introduced to match contemporary monitors?",opts:["1:1","16:9","21:9","3:2"],ans:1,exp:"Recognizing the global hardware shift from square CRT monitors to modern widescreen LCDs and HD projectors, Microsoft permanently altered the fundamental slide canvas dimensions in PPT 2013 onwards. The default aspect ratio shifted from the boxy 4:3 format to the cinematic 16:9 widescreen format, filling modern displays perfectly."},hi:{q:"पुराने PowerPoint संस्करणों (2010 और पूर्व) में, डिफ़ॉल्ट स्लाइड आकार पहलू अनुपात (Slide Size aspect ratio) 4:3 था। समकालीन मॉनिटरों से मेल खाने के लिए पेश किया गया आधुनिक डिफ़ॉल्ट स्लाइड आकार पहलू अनुपात क्या है?",opts:["1:1","16:9","21:9","3:2"],ans:1,exp:"स्क्वायर CRT मॉनिटर से आधुनिक वाइडस्क्रीन एलसीडी और एचडी प्रोजेक्टर में वैश्विक हार्डवेयर बदलाव को पहचानते हुए, Microsoft ने पीपीटी 2013 से बाद के मौलिक स्लाइड कैनवास आयामों को स्थायी रूप से बदल दिया। डिफ़ॉल्ट पहलू अनुपात बॉक्सी 4:3 प्रारूप से सिनेमाई 16:9 वाइडस्क्रीन प्रारूप में स्थानांतरित हो गया, जो आधुनिक डिस्प्ले को पूरी तरह से भरता है।"}},
{type:"mcq",diff:"hard",en:{q:"If a user saves a PowerPoint presentation as an .rtf (Rich Text Format) file, what specific data is exported?",opts:["All slides as high-quality JPEG images","Only the VBA macro code","Strictly the textual data contained within the structural Title and Content placeholders (the Outline)","A completely formatted video format"],ans:2,exp:"Exporting to RTF strips away absolutely all graphics, shapes, background colors, and slide geometry. It extracts solely the raw text hierarchy (the Outline view) that was typed specifically into the master Title and bulleted Content placeholders, generating a lightweight text document ideal for importing into MS Word."},hi:{q:"यदि कोई उपयोगकर्ता PowerPoint प्रेजेंटेशन को .rtf (रिच टेक्स्ट फॉर्मेट) फ़ाइल के रूप में सहेजता है, तो कौन सा विशिष्ट डेटा निर्यात किया जाता है?",opts:["सभी स्लाइड उच्च-गुणवत्ता वाली JPEG छवियों के रूप में","केवल VBA मैक्रो कोड","सख्ती से संरचनात्मक शीर्षक और सामग्री प्लेसहोल्डर्स (रूपरेखा) के भीतर निहित पाठ्य डेटा","पूरी तरह से स्वरूपित वीडियो प्रारूप"],ans:2,exp:"आरटीएफ (RTF) में निर्यात करने से बिल्कुल सभी ग्राफिक्स, आकार, पृष्ठभूमि रंग और स्लाइड ज्यामिति दूर हो जाती है। यह पूरी तरह से कच्चे पाठ पदानुक्रम (आउटलाइन दृश्य) को निकालता है जो विशेष रूप से मास्टर शीर्षक और बुलेटेड सामग्री प्लेसहोल्डर्स में टाइप किया गया था, एमएस वर्ड में आयात करने के लिए आदर्श एक हल्का पाठ दस्तावेज़ उत्पन्न करता है।"}},
{type:"mcq",diff:"hard",en:{q:"During document collaboration, when a colleague leaves a Comment, how does the original author mark the discussion as finalized without deleting the comment thread?",opts:["They click 'Mark as Final'","They click 'Resolve' on the comment pane","They lock the layer in the Selection Pane","They change the text color to grey"],ans:1,exp:"Modern collaboration features allow users to reply to specific comments in a thread. Once the editing issue is handled, the author clicks 'Resolve'. This visually greys out the comment thread to signify completion, keeping the historical communication log intact within the file without cluttering the active feedback loop."},hi:{q:"दस्तावेज़ सहयोग के दौरान, जब कोई सहकर्मी टिप्पणी (Comment) छोड़ता है, तो मूल लेखक टिप्पणी थ्रेड को हटाए बिना चर्चा को कैसे अंतिम रूप देता है?",opts:["वे 'मार्क एज़ फ़ाइनल' पर क्लिक करते हैं","वे टिप्पणी फलक (comment pane) पर 'समाधान करें' (Resolve) पर क्लिक करते हैं","वे चयन फलक (Selection Pane) में परत (layer) को लॉक करते हैं","वे टेक्स्ट का रंग बदलकर ग्रे कर देते हैं"],ans:1,exp:"आधुनिक सहयोग सुविधाएँ उपयोगकर्ताओं को एक थ्रेड में विशिष्ट टिप्पणियों का उत्तर देने की अनुमति देती हैं। संपादन समस्या हल हो जाने के बाद, लेखक 'समाधान करें' (Resolve) पर क्लिक करता है। यह पूर्णता को दर्शाने के लिए टिप्पणी थ्रेड को दृष्टिगत रूप से ग्रे कर देता है, सक्रिय फीडबैक लूप को अव्यवस्थित किए बिना फ़ाइल के भीतर ऐतिहासिक संचार लॉग को बरकरार रखता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which advanced Picture Tools feature allows you to perfectly mask a rectangular photograph so it appears as a perfect circle or star?",opts:["Compress Picture","Artistic Effects","Crop to Shape","Picture Borders"],ans:2,exp:"The 'Crop to Shape' command (located in the Crop drop-down menu) acts as a geometric cookie-cutter. Instead of merely trimming the horizontal or vertical edges of an image, it forces the photograph's boundaries to perfectly map onto any vector shape (like a circle, heart, or arrow), instantly masking the excess image data."},hi:{q:"कौन सी उन्नत पिक्चर टूल्स (Picture Tools) सुविधा आपको आयताकार तस्वीर को पूरी तरह से मास्क करने की अनुमति देती है ताकि यह एक आदर्श वृत्त या तारे के रूप में दिखाई दे?",opts:["पिक्चर कंप्रेस करें (Compress Picture)","कलात्मक प्रभाव (Artistic Effects)","शेप में क्रॉप करें (Crop to Shape)","पिक्चर बॉर्डर (Picture Borders)"],ans:2,exp:"'क्रॉप टू शेप' कमांड (क्रॉप ड्रॉप-डाउन मेनू में स्थित) ज्यामितीय कुकी-कटर के रूप में कार्य करता है। किसी छवि के क्षैतिज या ऊर्ध्वाधर किनारों को केवल ट्रिम करने के बजाय, यह तस्वीर की सीमाओं को किसी भी वेक्टर आकार (जैसे सर्कल, दिल, या तीर) पर पूरी तरह से मैप करने के लिए मजबूर करता है, तुरंत अतिरिक्त छवि डेटा को मास्क करता है।"}},
{type:"mcq",diff:"hard",en:{q:"To prevent a 3-minute embedded video from playing its boring 30-second intro, which specific Video Tool should you utilize to adjust the physical start marker?",opts:["Video Formatting","Fade In","Trim Video","Crop Video"],ans:2,exp:"The 'Trim Video' utility (found in the Video Tools > Playback tab) launches a mini non-linear editor. It provides a visual timeline where the user can drag a green start marker and a red end marker. PowerPoint will then completely ignore the excluded footage, playing only the trimmed segment during the slide show."},hi:{q:"3-मिनट के एम्बेडेड वीडियो को अपने उबाऊ 30-सेकंड के परिचय को चलाने से रोकने के लिए, आपको भौतिक स्टार्ट मार्कर को समायोजित करने के लिए किस विशिष्ट वीडियो टूल का उपयोग करना चाहिए?",opts:["वीडियो फ़ॉर्मेटिंग","फेड इन (Fade In)","ट्रिम वीडियो (Trim Video)","क्रॉप वीडियो (Crop Video)"],ans:2,exp:"'ट्रिम वीडियो' उपयोगिता (वीडियो टूल > प्लेबैक टैब में पाया जाता है) एक मिनी गैर-रैखिक संपादक लॉन्च करता है। यह एक दृश्य समयरेखा प्रदान करता है जहां उपयोगकर्ता एक हरे स्टार्ट मार्कर और एक लाल एंड मार्कर को खींच सकता है। PowerPoint तब पूरी तरह से बाहर किए गए फुटेज को अनदेखा कर देगा, स्लाइड शो के दौरान केवल छंटनी वाले (trimmed) खंड को चलाएगा।"}},
{type:"mcq",diff:"hard",en:{q:"Under File > Export, PowerPoint can render the entire presentation, including all precise animation timings, transitions, and recorded audio, into a single standalone file. Which extension represents this?",opts:[".pdf",".mp4",".rtf",".docx"],ans:1,exp:"By selecting 'Create a Video', the PowerPoint rendering engine physically records the entire slide show playback, baking in all transitions, timed animations, and voiceovers, compiling it into an MPEG-4 Video (.mp4) or WMV file. This allows the presentation to be uploaded to YouTube or played on a device without PowerPoint installed."},hi:{q:"File > Export के अंतर्गत, PowerPoint पूरी प्रस्तुति को रेंडर कर सकता है, जिसमें सभी सटीक एनिमेशन टाइमिंग, ट्रांज़िशन और रिकॉर्ड किए गए ऑडियो को एक स्टैंडअलोन फ़ाइल में शामिल किया जा सकता है। कौन सा एक्सटेंशन इसका प्रतिनिधित्व करता है?",opts:[".pdf",".mp4",".rtf",".docx"],ans:1,exp:"'वीडियो बनाएं' (Create a Video) का चयन करके, PowerPoint रेंडरिंग इंजन भौतिक रूप से संपूर्ण स्लाइड शो प्लेबैक को रिकॉर्ड करता है, सभी ट्रांज़िशन, टाइम्ड एनिमेशन और वॉयसओवर में बेकिंग करता है, इसे एमपीईजी -4 वीडियो (.mp4) या डब्लूएमवी (WMV) फ़ाइल में संकलित करता है। यह प्रस्तुति को YouTube पर अपलोड करने या PowerPoint स्थापित किए बिना किसी डिवाइस पर चलाने की अनुमति देता है।"}},
{type:"mcq",diff:"hard",en:{q:"In the Animation Pane, if you want four distinct pictures to appear at the exact same millisecond rather than one by one, which timing setting must be applied to the animations?",opts:["Start On Click","Start With Previous","Start After Previous","Trigger on Bookmark"],ans:1,exp:"The Animation Pane handles sequential timing. Setting an animation to 'Start With Previous' groups its trigger timeline identically with the animation directly above it in the stack. Consequently, the calculation engine fires both animations simultaneously, creating synchronized, parallel movement on the slide."},hi:{q:"एनिमेशन पैन (Animation Pane) में, यदि आप चाहते हैं कि चार अलग-अलग चित्र एक के बाद एक के बजाय ठीक उसी मिलीसेकंड में दिखाई दें, तो एनिमेशन पर कौन सी टाइमिंग सेटिंग लागू की जानी चाहिए?",opts:["क्लिक पर शुरू करें (Start On Click)","पिछले के साथ शुरू करें (Start With Previous)","पिछले के बाद शुरू करें (Start After Previous)","बुकमार्क पर ट्रिगर करें (Trigger on Bookmark)"],ans:1,exp:"एनीमेशन पैन अनुक्रमिक समय को संभालता है। किसी एनीमेशन को 'पिछले के साथ शुरू करें' पर सेट करने से इसके ट्रिगर टाइमलाइन को स्टैक में सीधे इसके ऊपर एनीमेशन के साथ समूहित किया जाता है। नतीजतन, गणना इंजन स्लाइड पर सिंक्रनाइज़, समानांतर आंदोलन (parallel movement) बनाते हुए एक साथ दोनों एनिमेशन को फायर करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which obscure master view is strictly used to modify the structural layout, headers, footers, and background watermarks of the paper grids given to the audience for note-taking?",opts:["Slide Master","Notes Master","Handout Master","Reading View"],ans:2,exp:"The 'Handout Master' (accessible via the View tab) governs the hard-copy print layout. It allows the presenter to globally manipulate the size of the slide thumbnails printed on the page, and insert corporate logos, dynamic dates, or page numbers into the margins specifically for the distributed audience paper packets."},hi:{q:"नोट लेने के लिए दर्शकों को दिए गए पेपर ग्रिड के संरचनात्मक लेआउट, हेडर, फुटर और पृष्ठभूमि वॉटरमार्क को संशोधित करने के लिए किस अस्पष्ट मास्टर व्यू (master view) का सख्ती से उपयोग किया जाता है?",opts:["स्लाइड मास्टर","नोट्स मास्टर","हैंडआउट मास्टर (Handout Master)","रीडिंग व्यू"],ans:2,exp:"'हैंडआउट मास्टर' (दृश्य टैब के माध्यम से सुलभ) हार्ड-कॉपी प्रिंट लेआउट को नियंत्रित करता है। यह प्रस्तुतकर्ता को पृष्ठ पर मुद्रित स्लाइड थंबनेल के आकार को विश्व स्तर पर हेरफेर करने की अनुमति देता है, और विशेष रूप से वितरित दर्शकों के पेपर पैकेट के लिए मार्जिन में कॉर्पोरेट लोगो, गतिशील तिथियां या पृष्ठ संख्या सम्मिलित करता है।"}},
{type:"tf",diff:"hard",en:{q:"The 'Mark as Final' command permanently encrypts the presentation so it can never be edited again under any circumstances.",opts:["True","False"],ans:1,exp:"False. 'Mark as Final' is purely an administrative courtesy warning, not a security encryption. It opens the file in read-only mode to prevent accidental changes, but any user can easily ignore it by clicking the 'Edit Anyway' button on the yellow warning bar at the top of the screen."},hi:{q:"'मार्क एज़ फ़ाइनल' (Mark as Final) कमांड प्रेजेंटेशन को स्थायी रूप से एन्क्रिप्ट कर देता है ताकि इसे किसी भी परिस्थिति में फिर कभी संपादित न किया जा सके।",opts:["सही","गलत"],ans:1,exp:"गलत। 'मार्क एज़ फ़ाइनल' विशुद्ध रूप से एक प्रशासनिक शिष्टाचार चेतावनी है, न कि सुरक्षा एन्क्रिप्शन। यह आकस्मिक परिवर्तनों को रोकने के लिए फ़ाइल को केवल पढ़ने के लिए (read-only) मोड में खोलता है, लेकिन कोई भी उपयोगकर्ता स्क्रीन के शीर्ष पर पीले रंग की चेतावनी पट्टी पर 'संपादित करें वैसे भी' (Edit Anyway) बटन पर क्लिक करके इसे आसानी से अनदेखा कर सकता है।"}},
{type:"tf",diff:"hard",en:{q:"When utilizing 'Presenter View' in a dual-monitor setup, the audience sees exactly the same screen containing the speaker notes as the presenter does.",opts:["True","False"],ans:1,exp:"False. The entire architectural purpose of Presenter View is to split the visual feed. The audience sees strictly the full-screen slide on the secondary monitor (projector). The primary monitor (the laptop) uniquely displays the complex control dashboard, exposing the speaker notes, timers, and upcoming slides solely to the presenter."},hi:{q:"दोहरे मॉनिटर सेटअप में 'प्रेजेंटर व्यू' (Presenter View) का उपयोग करते समय, दर्शकों को स्पीकर नोट्स वाली बिल्कुल वही स्क्रीन दिखाई देती है जो प्रस्तुतकर्ता करता है।",opts:["सही","गलत"],ans:1,exp:"गलत। प्रेजेंटर व्यू का पूरा वास्तुशिल्प उद्देश्य विज़ुअल फ़ीड को विभाजित करना है। दर्शकों को सेकेंडरी मॉनिटर (प्रोजेक्टर) पर सख्ती से फुल-स्क्रीन स्लाइड दिखाई देती है। प्राथमिक मॉनिटर (लैपटॉप) विशिष्ट रूप से जटिल नियंत्रण डैशबोर्ड प्रदर्शित करता है, जो स्पीकर नोट्स, टाइमर और आगामी स्लाइड को केवल प्रस्तुतकर्ता के सामने उजागर करता है।"}}
];
